const QUESTIONS_CSV = "topic_code,stem,choice_a,choice_b,choice_c,correct,explanation\n\"PM\",\"An analyst gathers the following information about a company: Payables turnover 8 Inventory turnover 2 Receivables turnover 10 If all purchases and sales were made on credit, the cash conversion cycle (based on a 360- day year) is:\",\"less than the utility generated for a risk-averse investor.\",\"equal to the utility generated for a risk-averse investor.\",\"greater than the utility generated for a risk-averse investor.\",\"B\",\"B. Correct because a risk-free asset (0 = 0) generates the same utility for all individuals. If 5:= 0, then U = E(r) - 1/2(A)(0?) = E(r) for all individuals.\"\n\"PM\",\"The diversification ratio of a portfolio is best described as the ratio of the: A standard deviation of the equally weighted portfolio's returns to the average\",\"standard deviation of the individual securities’ returns.\",\"standard deviation of the market-capitalization-weighted portfolio's returns to the\",\"standard deviation of the equally weighted portfolio's returns. C. average standard deviation of the individual securities’ returns to the standard deviation of the market-capitalization-weighted portfolio’s returns.\",\"A\",\"A. Correct because a simple measure of the value of diversification is calculated as the ratio of the standard deviation of the equally weighted portfolio to the standard deviation of the randomly selected security. This ratio may be referred to as the diversification ratio. In the example of the 5-stock portfolio given, the equally weighted portfolio’s standard deviation is approximately 71 percent of the average standard deviation of the 5 stocks (24.9%); i.e., the denominator is the average s\"\n\"PM\",\"Which of the following is most likely a consequence of the illusion of control bias?\",\"An investor's portfolio turnover is too low.\",\"Theinvestor's portfolio contains concentrated positions in companies.\",\"An investor uses a simple forecasting model for portfolio construction.\",\"B\",\"B. Correct because as a result of illusion of control bias, FMPs [financial market participants] may inadequately diversify portfolios. Research has found that some investors prefer to invest in companies that they feel they have control over, such as the companies they work for, leading them to hold concentrated positions.\"\n\"PM\",\"Which of the following best describes a potential consequence of the regret-aversion bias for financial market participants?\",\"Engaging in herding behaviour\",\"Borrowing excessively to finance present consumption\",\"Misidentifying risk tolerances because of how questions about risk tolerance were framed\",\"A\",\"A Correct because as a result of regret-aversion bias, FMPs [financial market participants] may engage in herding behavior. FMPs may feel safer in popular investments in order to limit potential future regret. Regret-aversion bias is an emotional bias in which people tend to avoid making decisions out of fear that the decision will turn out poorly.\"\n\"PM\",\"Exchange-traded funds (ETFs):\",\"are priced once a trading day.\",\"usually pay out dividends to shareholders.\",\"are generally structured as closed-end funds.\",\"B\",\"B. Correct because dividends on ETFs are paid out to the shareholders whereas mutual funds usually reinvest the dividends.\"\n\"PM\",\"Two assets have the following characteristics: Variance of returns for Asset 1 0.05 Variance of returns for Asset 2 0.06 Correlation of returns between Asset 1 and Asset2 0.75 The variance of returns for an equally weighted portfolio of the two assets is closest to\",\"0.038.\",\"0.048.\",\"0.055.\",\"B\",\"B. Correct because for a two asset portfolio, the expression for portfolio variance simplifies to the following using correlation: Op = WG? + Wr0z + 2WiW:0120105, Where wi is the weight of asset i in the portfolio, oi: is the variance of asset i, and pij is the correlation between the returns of assets i and j. Here, op = (0.5):(0.05) + (0.5)2(0.06) + 2(0.5)(0.5)(0.75)(0.05)05(0.06)es = 0.0125 + 0.015 + 0.0205396 = 0.04804 ~ 0.048.\"\n\"PM\",\"An analyst gathers the following information about a portfolio and the market: Portfolio return 7.0% Market return 5.0% Risk-free return 1.0% Portfolio beta 12 Jensen's alpha for the portfolio is:\",\"0.0%.\",\"1.2%.>\",\"2.2%.\",\"B\",\"B. Correct because Jensen's alpha is defined as the portfolio return less (the risk-free rate plus the portfolio beta times (the market return minus the risk-free rate). Therefore, Jensen's alpha = R, — [Ry+ Bp(Ra — R)] = 7% - (1% + 1.2 x (5% — 1%)) = 7.0% ~ 5.8% = 1.2%.\"\n\"PM\",\"The Markowitz efficient frontier is best described as a curve that:\",\"lies above and to the left of the minimum-variance frontier.\",\"connects the minimum-variance portfolios for all possible returns.\",\"contains all portfolios of risky assets that rational, risk-averse investors will choose.\",\"C\",\"C. Correct because the Markowitz efficient frontier contains all portfolios of risky assets that rational, risk-averse investors will choose.\"\n\"PM\",\"An analyst gathers the following information: Risk-free rate 2% Expected return of the market portfolio 10% Standard deviation of the market portfolio 20% Standard deviation of the security 35% Correlation between the security and the market 0.8 8 According to the CAPM, the expected return of the security is closest to\",\"5.7%.\",\"13.2%.\",\"16.0%.\",\"B\",\"B. Correct because the expected return of the security can be calculated using the CAPM equation: E(R) = R,+ B[E(R.) — R}. The beta of the security can be calculated using the equation B = (pi, x oi)/om. Therefore, B = (0.8 x 35%)/20% = 1.4. Beta is the product of the asset's correlation with the market with a ratio of standard deviations of return (i.e, the ratio of the asset's standard deviation to the market's). Therefore, using the CAPM equation: E(R) = 2% + 1.4 x (10% - 2%) = 13.2%.\"\n\"PM\",\"The risk-return profile of a portfolio’s strategic asset allocation is most likely determined by the expected returns and risks of the individual asset classes and the:\",\"correlations between those asset classes.\",\"use of security selection for each of those asset classes.\",\"allowable deviation of portfolio weights from policy weights for those asset classes.\",\"A\",\"A. Correct because the risk-return profile of the strategic asset allocation depends on the expected returns and risks of the individual asset classes, as well as the correlation between those asset classes.\"\n\"PM\",\"‘Which of the following is best classified as a financial risk?\",\"Tax risk\",\"Credit risk\",\"Accounting risk\",\"B\",\"B. Correct because the risk management industry has come to classify three types of risks as primarily financial in nature and the second primary financial risk is credit risk.\"\n\"PM\",\"An analyst gathers the following information about three stocks: —BetaStandard Deviation of Returns Stock1 0.9 17% Stock2 1.1 18% Stock3 1.2 16% If the standard deviation of market returns is equal to 10%, the stock with the highest nonsystematic risk is:\",\"Stock 1.\",\"Stock2.\",\"Stock 3.\",\"A\",\"A. Correct because Total variance = Systematic variance + Nonsystematic variance, which can be written as oi: = Bizomz + oez. Thus, ce: = oi - Bizom:. Thus, nonsystematic variance for Stock 1 is equal to (0.17): - (0.9)2(0.1): = 0.0208. For Stock 2, this is equal to (0.18)2 - (1.1):(0.1)r = 0.0203. For Stock 3, this is equal to (0.16): ~ (1.2):(0.1): = 0.0112. Therefore, Stock 1 has the highest nonsystematic variance and the highest idiosyncratic risk. Nonsystematic risk is the risk that pertain\"\n\"PM\",\"Which of the following metrics is most appropriate to estimate a bond's average extreme loss?\",\"VaR of loss\",\"Standard deviation of loss\",\"Expected loss given default\",\"C\",\"[0 Correct because the statistics used to estimate VaR can be used to gauge average extreme losses. Conditional VaR or CVaR is a common tail loss measure, defined as the weighted average of all loss outcomes in the statistical distribution that exceed the VaR loss. Another tail risk metric in the credit risk space that is analogous to CVaR is expected loss given default, which answers the Answer for a debt security, If the underlying company or asset defaults, how much do we lose on average?\"\n\"PM\",\"According to capital market theory, an efficient market does not reward investors for taking on:\",\"market risk.\",\"systematic risk.\",\"idiosyncratic risk.\",\"C\",\"C Correct because we can assume that in an efficient market, no incremental reward can be earned for taking on diversifiable risk. Nonsystematic risk is the risk that pertains to a single company or industry and is also known as company-specific, industry-specific, diversifiable, or idiosyncratic risk. a4\"\n\"PM\",\"An investor gathers the following information about a security and the market: Security's beta 0.35 Standard deviation of the security's returns 12% Standard deviation of market returns 18% The correlation between the security's returns and the market's returns is closest to\",\"0.2.\",\"0.5.\",\"0.8.\",\"B\",\"B. Correct because B= pw x 0/0, Where pi denotes the correlation between the asset returns and the market returns, and 6: and on denote the standard deviation of the asset returns and the market returns, respectively. Thus, correlation pi = Bi x Ga/; = 0.35 x 0.18/0.12 = 0.525 = 0.5.\"\n\"PM\",\"An analyst gathers the following information: — Standard Deviation of ReturnsBeta Asset 70% 18 Market portfolio 35% 1.0 The covariance between the returns of the asset and the market is closest to\",\"0.22.\",\"0.40.\",\"0.90.\",\"A\",\"A Correct because, given the beta of an asset (8), the covariance between the asset returns (R) and the market portfolio returns (R.) is given by: Cov(R,R.) = B; x 0.2 = 1.8 x 0.35:= 0.22.\"\n\"PM\",\"An adviser gathers the following information about a client's retirement income needs: + The current balance of the client's retirement fund is $150,000. « The client plans to retire in 15 years’ time. + $500,000 in today's money is needed to fund retirement. + No further retirement fund contributions will be made. Inflation is expected to average 2% per year over the next 15 years. Based only on the above information and ignoring taxes, the minimum annual rate of return required to meetthe client's retirement income objective is closest to:\",\"6.2%.\",\"8.4%.\",\"10.5%.\",\"C\",\"C. Correct because, at 2% annual inflation, $500,000 in today's money equates to $500,00(1.02) = $672,934 in 15 years’ time. Since no further contributions to the retirement fund will be made, the current savings of $150,000 must grow to at least $672,934 in 15 years’ time to meet the individual's retirement income objective. Hence, the minimum required rate of return, r, satisfies $150,000(1 + rs = $672,934, giving r = [$672,934/$150,000] - 1 = 0.105 = 10.5%. Calculator solution: (1) N = 15; I/\"\n\"QM\",\"An investor purchases a stock for $100. Immediately after receiving a dividend of $7, the investor sells the stock for $107. The holding period return of the investment is closest to\",\"0%.\",\"7%.\",\"14%.\",\"C\",\"C. Correct because a holding period return is the return earned from holding an asset for a single specified period of time. This return can be generalized and shown as a mathematical expression in which P is the price and I is the income: R = (Py = Po + D,)/P: Thus, R= ($107 - $100 + $7)/$100 = $14/$100 = 14%.\"\n\"QM\",\"A test of independence is based on the data in a contingency table with 5 rows and 4 columns. Using a nonparametric test statistic that is chi-square distributed, the number ofdegrees of freedom is:\",\"7.\",\"12.\",\"20.\",\"B\",\"B. Correct because for a contingency table we can perform a test of independence using a nonparametric test statistic that is chi-square distributed this test statistic has (r - 1)(c - 1) degrees of freedom, where r is the number of rows and c is the number of columns. Here, r = 5 and ¢ = 4, so degrees of freedom = (5-1)(4-1) =4 x3 =12.\"\n\"QM\",\"Ifa unimodal return distribution is negatively skewed, which of the following mostlikely has the highest value?\",\"Mean\",\"Mode\",\"Median\",\"B\",\"B. Correct because for the continuous negatively skewed unimodal distribution, the mean is less than the median, which is less than the mode. Therefore, the mode has the highest value.\"\n\"QM\",\"For a continuous positively skewed unimodal distribution:\",\"both the mode and the median are less than the mean.\",\"both the mode and the median are greater than the mean.\",\"the mode is less than the mean and the median is greater than the mean.\",\"A\",\"A. Correct because for a continuous positively skewed unimodal distribution, the mode is less than the median, which is less than the mean.\"\n\"QM\",\"An analyst draws samples from an original sample to estimate the standard error of apopulation ‘mean. Which of the following best describes this sampling procedure?\",\"Bootstrap method\",\"Cluster sampling method\",\"Convenience sampling method\",\"A\",\"A. Correctbecause in bootstrap, we repeatedly draw samples from the original sample, and each resample is of the same size as the original sample. Note that each item drawn is replaced for the next draw (i.e. the identical element is put back into the group so that it can be drawn more than once). Assuming we are looking to find the standard error of sample mean, we take many resamples and then compute the mean of each resample.\"\n\"QM\",\"An investor records the following information and transactions for a stock: YearPrice per Share at Beginning of Year Cash Flow at Beginning of Year 1 $100 $100 used to purchase one share 2 $100 $9 received in dividends and not reinvested 3 $100 $100 received from selling one share The investor's money-weighted rate of return is closest to\",\"4.4%.\",\"4.5%.\",\"C. 4.6%.\",\"C\",\"C. Correct because it is the money-weighted return when the dividend is not reinvested. Calculator solution: CFO =-100, CF1 = 9, CF2 = 100, compute IRR = 4.601% ~ 4.6%. 91\"\n\"QM\",\"The null hypothesis for the F-distributed test statistic in a simple linear regression modeltests whether the:\",\"slope is equal to zero.\",\"intercept is equal to zero.\",\"slope is not equal to zero.\",\"A\",\"A. Correct because in regression analysis, we can use an F-distributed test statistic to test whether the slopes in a regression are equal to zero, with the slopes designated as b,, against the alternative hypothesis that at least one slope is not equal to zero for simple linear regression, these hypotheses simplify to Hu: by = 0. Ha: by #0.\"\n\"QM\",\"Which of the following is most likely used to detect sentiment shifts in an analyst'scommentary?\",\"Tokenization\",\"Data curation\",\"Natural language processing\",\"C\",\"C. Correctbecause NLP [natural language processing] may be used to monitor analyst commentary to aid investment decision making. Since analysts tend not to change their buy, hold, and sell recommendations for a company frequently, they may instead offer nuanced commentary without making a change in their investment recommendation. NLP can, therefore, be used to detect, monitor, and tag shifts in sentiment, potentially ahead of an analyst's recommendation change. 92\"\n\"QM\",\"Roy's safety-first criterion:\",\"evaluates only downside risk.\",\"uses semideviation as a risk measure.\",\"assumes asset prices are normally distributed.\",\"A\",\"A. Correct because mean-variance analysis generally considers risk symmetrically in the sense that standard deviation captures variability both above and below the mean. An alternative approach evaluates only downside risk. We discuss one such approach, safety- first rules, as it provides an excellent illustration of the application of normal distribution theory to practical investment problems. Safety-first rules focus on shortfall risk, the risk that portfolio value will fall below some minimu\"\n\"QM\",\"An analyst examines 30 paired monthly returns for two stock indexes. To determine if themean\",\"difference of the returns is zero, the number of degrees of freedom of the t-test is: A. 28.\",\"29.\",\"58.\",\"B\",\"B. Correct because the t-statistic for a paired comparisons test has n — 1 degrees of freedom, where n is the number of pairs of observations. When n = 30, the number of degrees of freedom is 30 - 1 = 29.\"\n\"QM\",\"For a given dataset with different non-negative observations, which of the following willhave the largest value?\",\"Harmonic mean\",\"Arithmetic mean\",\"Geometric mean\",\"B\",\"B. Correct because the arithmetic mean of a given dataset with different observations is higher than the harmonic and geometric means. Unless all the observations in a dataset have the same value, the harmonic mean is less than the geometric mean, which, in turn, is less than the arithmetic mean.\"\n\"QM\",\"The central limit theorem:\",\"requires that the population be approximately normally distributed.\",\"implies that the sample mean is a consistent estimator of the population mean.\",\"states that the product of independent random variables is normally distributed.\",\"B\",\"B. Correct because the central limit theorem states that the variance of the distribution of the sample mean is o2/n. The positive square root of variance is standard deviation. 9 The standard deviation of a sample statistic is known as the standard error of thestatistic. The sample mean, in addition to being an efficient estimator, is also a consistent estimator of the population mean: As sample size n goes to infinity, its standard error, 98 a/Vn, goes to 0 and its sampling distribution become\"\n\"QM\",\"The standard error of the estimate in a simple linear regression is best described as:\",\"arelative measure of fit for the regression.\",\"the percentage of the variation of the dependent variable that is explained by the\",\"independent variable. C. a measure of the distance between the observed values of the dependent variable and those predicted from the estimated regression.\",\"C\",\"C. Correct because the standard error of the estimate is a measure of the distance between the observed values of the dependent variable and those predicted from the estimated regression.\"\n\"QM\",\"An analyst gathers the following information abouta portfolio's returns: Year Return (%) 1 6% 2 7% 3 3% 4 2% 5 4% If the target return is 5%, the target downside deviation is closest to\",\"1.7%.\",\"1.9%.\",\"2.2%.\",\"B\",\"B. Correct because the formula for target downside deviation is [E(X:- B)?/(n - 1)]>s, where X, is the return for the period, B is the target return and n is the total number of sample observations. Moreover, the summation is taken over only those observations x) that are less than or equal to the target B. YearReturn Deviations from the squared (%) target deviations 1 6 0 0 2 7 0 0 3 3 -2 4 4 2 -3 9 5 4 -1 1 C. Since the sum of squared deviations is 14, the target downside deviation = [14/(5 - \"\n\"QM\",\"An analyst gathers the following returns for seven funds: 12% 7% 5% 4% 8% 3% 3% The second quartile return is:A. 63\",\"4%.\",\"5%.\",\"6%.\",\"B\",\"B. Correct because the formula for the position of a percentile in an array with n entries sorted in ascending order is L, = ( n + 1) x y/100, where y is the percentage point at which we are dividing the distribution and L, is the location ( L) of the percentile ( P,) in the array sorted in ascending order. With seven entries, the location of the second quartile, or 50» percentile, is: L, = (7 + 1) x 50/100 = 4. When placing the funds’ returns in ascending order (3%; 3%; 4%; 5%; 7%; 8%; 12%), th\"\n\"QM\",\"Adiscrete random variable X has the following probability distribution: Probabilit Outcome Ee 0.20 35 0.30 50 0.50 80 The standard deviation of X is closest to\",\"18.73.\",\"20.00.\",\"22.91.\",\"A\",\"A. Correctbecause the expected value E(X) = ZnP(X)X = (0.20 x 35) + (0.30 x 50) + (0.50 x 80) = 62. The variance o*(X) = E{[X - E(X)]2} = ZurP(X)[X - E(X)]: = 0.20 x (35-62)2+ 0.30 x (50 - 62) + 0.50 x (80 - 62): = 351. Standard deviation is the positive square root of variance: o = 3512 = 18.73.\"\n\"QM\",\"Atree diagram contains the following information about the dividend per share payable by a company under two scenarios: Scenario Probability of Scenario Dividend per Probability of Dividend Share $2.00 0.80 Favorable 0.60 $1.50 0.20 $0.75 0.30 Unfavorable 0.40 $0.50 0.70 The expected dividend per share under the favorable scenario is closest to\",\"$1.14.\",\"$1.37.\",\"$1.90.\",\"C\",\"Gi Correct because the expected value of a random variable X given an event or scenario § is denoted E(X | 5). Suppose the random variable X can take on any one of n distinct outcomes X;, X;, ..., X. (these outcomes form a set of mutually exclusive and exhaustive events). The expected value of X conditional on S is the first outcome, X;, times the probability of the first outcome given S, P(X; | 5), plus the second outcome, X;, times the probability of the second outcome given S, P(X: | §), and \"\n\"QM\",\"Aninvestor invests a fixed amount of money into a fund each year for three years as follows: Year Price per Share 1 €14.00 2 €12.00 3 €17.00 The investor's average cost per share is closest to:\",\"€14.05.\",\"€14.33.\",\"€14.63.\",\"A\",\"A. Correct because the harmonic mean is used to determine the average price paid per 3 Vay =14.05. + J4 + y share when using cost averaging; 14 12 17 The weighted mean formula could also be used, where the weights would be the proportion of the total number of shares purchased. However, in order to use this method a fixed investment amount would need to be created.\"\n\"QM\",\"An analyst produces the following joint probability function for the returns on two companies, X and ¥: Return Return of ¥=15% of ¥=10% Return of Y=5% Return of X=20% 0.2 0 0 Return of X= 15% 0 0.4 0 Return of X = 10% 0 0 0.4 The expected returns of companies X and Y are 14% and 9%, respectively. The covarianceof returns between X and ¥ (in percent squared) is closest to:\",\"0.\",\"5.\",\"14.\",\"C\",\"C. Correct because the formula for calculating the covariance between random variables R« and Re is Cov(Ry,Rs) = EZP(Ru,Re)) (Ru — E[RA)) (Ra = E[Rs)). The expected return (given) for each company is: E[R] =0.2(20) + 0.4(15) + 0.4(10) = 4 + 6 + 4 = 14, E[Ry) = 0.2(15) + 0.4(10) + 0.4(5) =3 + 4 +2=9. Hence, Cov(RyR») = 0.2(20 - 14)(15 - 9) + 0.4(15 - 14)(10 - 9) + 0.4(10 - 14)(5 - 9)=0.2(6)(6) + 0.4(1)(1) + 0.4(-4)(-4) = 7.2 + 0.4 + 6.4 = 14. 105\"\n\"QM\",\"In evaluating portfolio performance, the return measure most affected by an addition offunds to the portfolio just before a market downturn is the:\",\"time-weighted return.\",\"arithmetic mean return.\",\"money-weighted return.\",\"C\",\"C. Correct because, if funds are added to a portfolio, the money-weighted rate of return puts a greater weight on the time period after the funds were added. (As a corollary, if funds are taken out of a portfolio, the money-weighted rate of return puts a greater weight on the time period before the funds were removed.) So, if a client gives an investment manager more funds to invest at an unfavorable time, the manager's money- weighted rate of return will tend to be depressed.\"\n\"QM\",\"An equally weighted portfolio consists of two securities, each with a standard deviation of3%. If the two securities’ returns are uncorrelated, the portfolio's standard deviation is closest to:\",\"0.0%.\",\"2.1%.\",\"3.0%.\",\"B\",\"B. Correct because the portfolio standard deviation is 2.1%; 3) - trove 5 = JO57GY + (05°C) + 200500 DON = ¥45 1.3 1206, using the formula 7% = TTT BCR E np RoR, which is equal to zero because the funds are uncorrelated; PR). Ry) =0.\"\n\"QM\",\"An investment requires 10 equal annual payments, starting today, and will pay out a lumpsum of $500,000 15 years from today. If the interest rate is 4% per year compounded annually, the required annual payment is closest to:\",\"$32,913.\",\"$34,230.\",\"$40,044.\",\"A\",\"A. Correctbecause the present value of the future lump sum payment is PV = FVa(1 107 +r)-N =$500,000(1 + 0.04) = $277,632.25. The 10 annual payments form an annuity due (since the payments start today) whose present value equals the present value of an ordinary annuity with 9 annual payments plus the first payment, i.e. PV =A + A[1-1/(1 +7r)¥]/r=A(1+ [1 -1/(1 + 0.04)5]/0.04) = 8.4353(A). Setting the PV of the cash outflows (the annuity) equal to the PV of the cash inflows (the return in 15 years\"\n\"QM\",\"A portfolio has a mean return of 1.0% and a standard deviation of returns of 2.7%. If thespecified minimum target return is 1.0%, the sample target semideviation is:\",\"less than 2.7%.\",\"equalto2.7%.\",\"greater than 2.7%.\",\"A\",\"A. Correct because the target downside deviation = [Z(X; - B)?/(n — 1)]es, where X, are the periodic returns below the target return, B is the target return, and n is the total number of periods. Since the sample has a standard deviation of 2.7%, it will have values below and above its mean of 1.0%. Since the target downside deviation ignores the deviations above the mean, it will be less than the standard deviation.\"\n\"QM\",\"A bank offers a savings account with a stated annual rate of 3% in the first year and 5% inthe second year. If returns are compounded quarterly and €90,000 is deposited in the account at the beginning of the first year, the account's value at the end of the second yearis closest to:\",\"€97,200.\",\"€97,335.\",\"€97,455.\",\"C\",\"C. Correct because the returns are compounded quarterly; 4 . 90001 + 2) ( +205 =97.455. 4 4\"\n\"QM\",\"A pension fund needs to pay a lump sum $10,000,000 to its participants in 15 years. If thefund is expected to earn 5% per year compounded semi-annually, the amount needed today to meet its liability in 15 years is closest to:\",\"$4,767,427.\",\"$4,810,171.\",\"$4,892,771.\",\"A\",\"A Correct because using the equation PV =FVN(1 + r./m)-Nm where m = number of compounding periods per year r.= quoted annual interest rate N =number of years we compute PV = $10,000,000 x (1 + 0.05/2)1= $4,767,426.85 ~ $4,767,427. In applying the equation, we use the periodic rate (in this case, the semi-annual rate) and the appropriate number of periods with semi-annual compounding. Alternative solution using a financial calculator in END mode: N =30; I/Y = 0.025; PMT = 0; FV = 10,000,000; CPT \"\n\"QM\",\"Which of the following is an underlying assumption of the simple linear regression model?The regression residuals:\",\"are normally distributed.\",\"have high correlations across observations.\",\"have different variances across observations.\",\"A\",\"A Correct because one of the four key assumptions we need to make t6 be able to draw valid conclusions from a simple linear regression mode is that regression residuals are normally distributed.\"\n\"QM\",\"An analyst tabulates the ranks of four paired observations of random variables X and Y as follows: Observatio Rank of X Rank of n Y 1 1 2 2 2 3 3 3 4 4 4 1 The Spearman rank correlation coefficient between Xand Yis closest to:A. —\",\"0.2.\",\"0.8.\",\"1.0.\",\"A\",\"A. Correct because with n as the sample size, the Spearman rank correlation is given by: r=1- (6 1d?)/(n(ne- 1))\"\" = 1 - 6(12)/(4(4*- 1)) = 1 - 6/5 =-1/5 = ~0.2, where the sum of squared differences in ranks Ydz= (2-1): + (3-2): + (4-3): + (1 - 4p=1+1+1+9=12\"\n\"QM\",\"A graphical depiction of a continuous distribution shows the left tail to be longer than theright tail. The distribution is best described as having:\",\"negative skewness.\",\"leptokurtosis.\",\"positive skewness.\",\"A\",\"A. Correct. A negatively skewed distribution appears as if the left tail has been pulled away from the mean. The average magnitude of negative deviations from the mean is larger than the average magnitude of positive deviations.\"\n\"QM\",\"Anonparametric test is most appropriate when: A. comparing differences between means.\",\"7s\",\"data are given in ranks.\",\"data meet distributional assumptions.\",\"B\",\"B. Correct. A nonparametric test is used under three circumstances: 1) when the data do not meet distributional assumptions, 2) when the data are given in ranks, and 3) when the hypothesis does not concern a parameter.\"\n\"EI\",\"Which of the following dates in the dividend chronology can fall on a weekend?\",\"The payment d\",\"ate.\",\"The record date. D. The ex-date.\",\"A\",\"A. Correct. The payment date can occur on a weekend or holiday unlike other pertinent dates, such as the ex-date and record date, which occur only on business days.\"\n\"EI\",\"An investor writes a put option on FTSE 100 Index futures. Which of the following best describes the investor's position with respect to the put contract and her exposure to the underlying index future, respectively?\",\"Long short\",\"Short, long\",\"Short, short\",\"B\",\"B. Correct. The investor has written a put contract, which means she is short the option. She, therefore, must satisfy the obligation to purchase the asset if requested to do so by the put owner. The investor has a long exposure to the risk of the underlying index future because she benefits when its quoted price increases—that is, when the put declines in value (or suffers a loss when its quoted price decreases as the put increases in value).\"\n\"EI\",\"Which of the following financial intermediaries is most likely to provide liquidity service to its clients?\",\"Brokers\",\"Dealers\",\"Exchanges\",\"B\",\"B. Correct. The service that dealers provide is liquidity. Liquidity is the ability to buy or sell with low transaction costs when investors want to trade. By allowing their clients to trade when they want to trade, dealers provide liquidity to them.\"\n\"EI\",\"The value effect market-pricing anomaly most likely occurs when stocks that have below- average price-to-earnings and market-to-book ratios, as well as above-average dividend yields, consistently outperform:\",\"large-cap stocks.\",\"growth stocks.\",\"stocks that have had negative earnings surprises.\",\"B\",\"B. Correct. The value effect occurs when value stocks, which are generally referred to as stocks that have below-average price-to-earnings and market-to-book ratios, as well as above-average dividend yields, outperform growth stocks consistently and for long periods.\"\n\"EI\",\"Downside and upside risk factors are most likely included in:\",\"an initial company research report only.\",\"a subsequent company research report only.\",\"both initial and subsequent research reports.\",\"C\",\"C. Correct because downside and upside risk factors are part of the company research report element \"\"Risks\"\" which is not only part of the initial company research report elements but also listed amongst the five elements for the subsequent company research report: 1. Front Matter, 2. Recommendation, 3. Analysis of New Information, 4. Valuation and 5. Risks. Answer 110f 154 Answer Solution\"\n\"EI\",\"With respect to behavioral biases, when investors tend to be slow to react to new information and continue to maintain their prior views, this is best described as:\",\"conservatism.\",\"herding behavior.\",\"representativeness.\",\"A\",\"A. Correct because conservative investors tend to be slow to react to new information and continue to maintain their prior views or forecasts.\"\n\"EI\",\"All else being equal, a reverse stock split results in:\",\"a decrease in the number of shares and an increase in the share price.\",\"an increase in the number of shares and a decrease in the share price.\",\"an increase in the number of shares and an increase in the share price.\",\"A\",\"A. Correct because a reverse stock split involves a reduction in the number of shares outstanding with a corresponding increase in share price.\"\n\"EI\",\"The dividend discount model assumes that dividends are paid:\",\"quarterly.\",\"halfyearly.\",\"at the end of each year.\",\"C\",\"C. Correct because according to the dividend discount model, each year's dividend is the expected dividend in year t, assumed to be paid at the end of the year.\"\n\"EI\",\"An analyst gathers the following information about a company and its common stock: Forward P/E 8 Required rate of return 12% Dividend growth rate 4% Using the Gordon growth model, the company's dividend payout ratio is closest to:\",\"8%.\",\"33%.\",\"64%.\",\"C\",\"C. Correct because according to the Gordon growth model equations ° ~~#and [YL therefore: r—s r-awhereF1= forecast for next year's earnings, p = dividend payout ratio, D, = forward dividend, r = required rate of return, and g = dividend growth rate, the dividend payout ratio p = 8.0 x (0.12 - 0.04) = 0.64 = 64%.\"\n\"EI\",\"Both equity and fixed income indexes can be categorized according to the:\",\"currency of payments.\",\"issuer's economic sector.\",\"degree of inflation protection.\",\"B\",\"B. Correctbecause both equity and fixed income indexes can be constructed according to sector. Similar to equities, fixed-income securities can be categorized according to the issuer’s economic sector, the issuer’s geographic region, or the economic development of the issuer’s geographic region.\"\n\"EI\",\"Fixed-income indexes most likely:\",\"are more easily replicated than equity indexes.\",\"require the provider to estimate the prices of some constituent securities.\",\"are created from a smaller universe of possible constituent securities than the universe of equity securities.\",\"B\",\"B. Correct because compared to equity indexes, fixed-income index providers must contact dealers to obtain current prices on constituent securities to update the index or they must estimate the prices of constituent securities using the prices of traded fixed- income securities with similar characteristics.\"\n\"EI\",\"As time passes after inception, the value of the price version of an index is:\",\"less than the value of the total return version.\",\"equal to the value of the total return version.\",\"greater than the value of the total return version.\",\"A\",\"A. Correct because at inception, the values of the price and total return versions ofan index are equal. As time passes, however, the value of the total return index will exceed the value of the price return index.\"\n\"EI\",\"The Global Industry Classification Standard (GICS) classifies industries based on:\",\"statistical similarities.\",\"business-cycle sensitivities.\",\"products and/or services supplied.\",\"C\",\"GC. Correct because examples of classification systems based on products and/or services include the commercial classification systems ... namely, the Global Industry Classification Standard (GICS).\"\n\"EI\",\"Which of the following industries or sectors is most likely classified as cyclical?\",\"Utilities\",\"Industrials\",\"Health care\",\"B\",\"B. Correct because examples of cyclical industries and broader sectors are autos, housing, basic materials, industrials, and technology.\"\n\"EI\",\"Free-cash-flow-to-equity is equal to cash flow from operations:\",\"less fixed capital investment less net borrowing.\",\"Jess fixed capital investment plus net borrowing.\",\"plus fixed capital investment less net borrowing.\",\"B\",\"B. Correct because free-cash-flow-to-equity (FCFE) can be expressed as FCFE = CFO — FCInv + Net borrowing where CFO is cash flow from operations and FCInv is fixed capital investment. 49\"\n\"EI\",\"An analyst gathers the following information about a security index: Period Return (4) 1 12 2 -8 3 2 If the index's value is 100 at the beginning of Period 1, the index's value at the end of Period 3 is closest to:\",\"103.\",\"105.\",\"[+ 106.\",\"B\",\"B. Correct because it is the value of the index at the end of period 3 = Beginning value x (1+Period 1 return) x (1 + Period 2 return) x (1 + Period 3 return) = 100 x (100 + 12%) x (100 - 8%) x (1 + 2%) = 105.10, which is closest to 105.\"\n\"EI\",\"If the cost to fill trades increases, the market's informational efficiency most likely:\",\"decreases.\",\"remains the same.\",\"increases.\",\"A\",\"A. Correct because how accurately prices reflect fundamental information depends on the costs of obtaining fundamental information and on the liquidity available to well- informed traders. If filling orders is very costly, informed trading may not be profitable. In that case, information-motivated traders will not commit resources to collect and analyze data and they will not trade. Without their research and their associated trading, prices would be less informative.\"\n\"EI\",\"An investor gathers the following information about a company and its common stock: Current dividend per share (Di) $1.00 Dividend payout ratio 60% ROE 12% If the required rate of return is 10%, using the Gordon growth model, the intrinsic value per share of the stock is closest to:\",\"$14.56.\",\"$19.23.\",\"$20.15.\",\"C\",\"[+ Correct because intrinsic value = Vo= D:/(r - g). Therefore, Vi = $1.048/(0.10 - 0.048) = $1.048/0.052 ~ $20.15, where: 9 = ROE x retention rate = 0.12 x (1 - 0.60) = 0.048; Dy =Dux (1+g) = $1.00 x 1.048 = $1.048.\"\n\"EI\",\"According to the efficient market hypothesis, if market prices reflect private information, the market is most likely:\",\"strong-form efficient.\",\"‘weak-form efficient only.\",\"semi-strong-form efficient, but not strong-form efficient.\",\"A\",\"A. Correct because in the case of a strong-form efficient market, insiders would not be able to earn abnormal returns from trading on the basis of private information. Market prices reflect private information under strong form market efficiency.\"\n\"EI\",\"All else being equal, which of the following preference share characteristics may contain provisions that entitle shareholders to an additional distribution of the company's assets upon liquidation, above the par value?\",\"Callable\",\"Cumulative\",\"Participating\",\"C\",\"C Correct because of the three characteristics, only the participating characteristic is most directly affected by liquidation of the company. Participating preference shares can also contain provisions that entitle shareholders to an additional distribution of the company's assets upon liquidation, above the par (or face) value of the preference shares.\"\n\"EI\",\"Athree-stage dividend discount model is most appropriate for valuing a company that is:\",\"mature.\",\"transitioning to maturity.\",\"youngand entering the growth phase.\",\"C\",\"C. Correct because one can make the case that a three-stage DDM would be most appropriate for a fairly young company, one that is just entering the growth phase.\"\n\"EI\",\"An equity index representing groups of securities classified on the basis of market capitalization is most likely\",\"styleindex.\",\"sector index.\",\"multi-market index.\",\"A\",\"A. Correct because style indexes represent groups of securities classified according to market capitalization, value, growth, or a combination of these characteristics. They are intended to reflect the investing styles of certain investors, such as the growth investor, value investor, or small-cap investor.\"\n\"EI\",\"An investor gathers the following data regarding three stocks: Stock Expected Rate of Investor's Required Rate of Return Return 1 9% 9% 2 13% 11% 3 15% 16% All else being equal, the investor should purchase:\",\"Stock 1.\",\"Stock 2.\",\"Stock 3.\",\"B\",\"B. Correct because the expected rate of return for Stock 2 exceeds the investor's required rate of return. In other words, the cost of equity can be thought of as the minimum expected rate of return that a company must offer its investors to purchase its shares in the primary market and to maintain its share price in the secondary market. If this expected rate of return is not maintained in the secondary market, then the share price will adjust so that it meets the minimum required rate of retur\"\n\"EI\",\"A $25 par value non-callable, non-convertible preferred share pays an annual dividend rate of 5%. If the required rate of return is 4%, the preferred share's intrinsic value is closest to:\",\"$25.25.\",\"$26.00.\",\"C. $31.25.\",\"C\",\"Cc. Correct because the estimated intrinsic value (Vs) is: © r, where D, = dividend, and r = the required rate of return. The D, = par value x annual dividend rate V,= $25 x 0.05 =$1.25.= $1.25 / 0.04 = $31.25.\"\n\"EI\",\"Which of the following market anomalies is best described as a time-series anomaly?\",\"Size effect\",\"Momentum\",\"Initial Public Offerings\",\"B\",\"B. Correct because the momentum anomaly is best described as a time-series anomaly. Momentum anomalies relate to short-term share price patterns where past price moves continued through time to move in the same direction.\"\n\"EI\",\"The observation that a large-capitalization company's stock price is inflated after the company releases unexpected good news at year end is most likely related to the:\",\"value effect.\",\"overreaction effect.\",\"turn-of-the-year effect”\",\"B\",\"B. Correct because the overreaction effect or anomaly is described as the propensity for investors to overreact to the release of unexpected public information. Therefore, stock 70 prices will be inflated (depressed) for those companies releasing good (bad) information. In other words, inflated (depressed) here means the change of value that is overshooting (undershooting) the fair (intrinsic) value after incorporating the new information, rather than the price action that goes up (down) itself,\"\n\"EI\",\"‘Within Porter's five forces framework, the power of buyers within an industry is most likely influenced by the:\",\"industry concentration.\",\"availability of lower priced alternative brands.\",\"number of customers for the industry's products.\",\"C\",\"C. Correctbecause the smaller the number of buyers, the more likely buyer power will increase. Bargaining Power of Customers. Affected by: size and concentration of customers, costs of switching to other suppliers, customers’ ability to produce the product or service themselves. Are customers able to force price reductions or better payment terms? This can affect the intensity of competition by exerting influence on suppliers regarding prices (and possibly other factors such as product quality).\"\n\"EI\",\"In the secondary market, funds flow from:\",\"traders to traders.\",\"issuers to investors.\",\"investors to issuers.\",\"A\",\"A. Correct because when investors sell securities to others, they trade in the secondary market. In the secondary market, funds flow between traders.\"\n\"EI\",\"In a well-functioning financial system, changes in asset prices primarily reflect changes in:\",\"execution costs.\",\"the demand for liquidity.\",\"fundamental asset values.\",\"C\",\"C. Correct because well functioning financial systems are characterized by prices that reflect fundamental values so that prices vary primarily in response to changes in fundamental values and not to demands for liquidity made by uninformed traders (informationally efficient markets).\"\n\"ETH\",\"Which of the following statements most likely reflects one of the six components of the CFA Code of Ethics? Candidates must:\",\"place the integrity of the investment profession above their own interests.\",\"promote the viability of the global capital markets for their employer's benefit.\",\"ignore unprofessional conduct displayed by others within the profession.\",\"A\",\"A. Correct. CFA charterholders and candidates must place the integrity of the investment profession and the interests of clients above their own personal interests.\"\n\"ETH\",\"A profession is most likely described as a group of people that:\",\"has a common level of basic knowledge about a particular subject.\",\"monitors its members based on an agreed-on code of ethics.\",\"puts the interests of its members first.\",\"B\",\"B. Correct. A profession is practiced by members who share and agree to adhere to a common code of ethics, and a profession is based on a specialized knowledge and skills and service to others.\"\n\"ETH\",\"Most societies would least likely consider ethical principles to include:\",\"justice.\",\"duplicity.\",\"diligence.\",\"B\",\"B. Correct. Most societies acknowledge the ethical principles of honesty, fairness or justice, diligence, and respect for the rights of others. Duplicity or deception would be in violation of most ethical principles.\"\n\"ETH\",\"Tibor Figeczky, CFA, is an equity trader at Global Investment Bank (GB). Figeczky traded the bank's investment portfolio profitably for the past three years and earned significant bonuses for his efforts. Subsequently, internal auditors of GB formally accused Figeczky of exceeding his trading authority and engaging in unauthorized trades. According to the CFA Institute Code of Ethics and Standards of Professional Conduct, Figeczky should most likely:\",\"disclose the complaint to CFA Institute.\",\"refuse further bonuses until the issue is resolved.\",\"request a temporary suspension of his CFA Institute membership.\",\"A\",\"A Correct as members and candidates must self-disclose on the annual Professional Conduct Statement all matters that Answer their professional conduct, such as involvement in civil litigation or a criminal investigation or being the subject of a written complaint.\"\n\"ETH\",\"Lisa Hajak, CFA, specialized in research on real estate companies at Cornerstone Country Bank for the past twenty years. Hajak recently started her own investment research firm, Hajak Investment Advisory. One of her former clients at Cornerstone asks Hajak to update a research report she wrote on a real estate company when she was at Cornerstone. Hajak updates the report, which she had copied to her personal computer without the bank's knowledge, and replaces references to the bank with her new firm, Hajak Investment Advisory. Hajak also incorporates the conclusions of a real estate study conducted by the Realtors Association that appeared in the Wall Street Journal. She references the Journal as her source in her report. She provides the revised report free of charge along with a cover letter for the bank's client to become a client of her firm. Concerning the reissued research report, Hajak least likely violated the CFA Institute Standards of Professional Conduct because she: 81\",\"solicited the bank's client.\",\"did not obtain consent to use the bank report.\",\"did not cite the actual source of the real estate study.\",\"A\",\"A. Correct as soliciting the bank's client did not violate Standard IV(A)-Loyalty because the manager is no longer an employee of the bank and there is no indication she obtained the client information from bank sources. The member, however, has violated Standard V(C)-Record Retention, because when she left the bank she took the property of the bank without express permission to do so. In addition, the analyst violated Standard 1(C)-Misrepresentation by creating research materials without attrib\"\n\"ETH\",\"‘Which of the following is a recommended procedure for compliance with the Standard relating to loyalty, prudence, and care? Members should:\",\"eliminate all actual and potential conflicts of interest.\",\"make their clients aware of all forms of manager compensation.\",\"submit to each client, at least annually, an itemized statement showing the funds and securities in custody.\",\"B\",\"B. Correctbecause a recommended procedure for Standard III (A), Loyalty, Prudence, and Care is members and candidates should make their clients aware of all forms of manager compensation.\"\n\"ETH\",\"According to the Standard relating to disclosure of conflicts, buy-side members should disclose to clients their:\",\"beneficial ownership in any security.\",\"firm's procedures for reporting requirements for personal transactions.\",\"firm's policies on blackout periods during which the member cannot trade for clients.\",\"B\",\"B. Correct because according to Standard VI(A), Disclosure of Conflicts, buy-side members and candidates should disclose their procedures for reporting requirements for personal transactions. Conflicts arising from personal investing are discussed more fully in the guidance for Standard VI(B). Therefore, not disclosing the procedure for a buy-side member is a violation.\"\n\"ETH\",\"Michael Mak, CFA, is a portfolio manager at an investment firm. After comprehensive research, Mak buys Advance One Tech's (AOT) stock for all his clients for whom the investment is suitable, He then buys AOT shares for his brother's fee-paying account, in which Mak has beneficial ownership. AOT's stock price declines significantly after a month, resulting in substantial losses for all his clients. Are Mak's actions consistent with the Standards?\",\"Yes\",\"No, Mak's actions are not consistent with the Standard relating to priority of\",\"transactions C. No, Mak's actions are not consistent with the Standard relating to diligence and reasonable basis\",\"B\",\"B. Correct because according to Standard VI(B), Priority of Transactions, family accounts that are client accounts should be treated like any other firm account and should neither be given special treatment nor be disadvantaged because of the family relationship. If a member or candidate has a beneficial ownership in the account, however, the member or candidate may be subject to preclearance or reporting requirements of the employer or applicable law. Mak should treat his brother's fee paying a\"\n\"ETH\",\"After thorough analysis, Algiris Vasilis, CFA, prepares a \"\"buy\"\" recommendation on a company's stock. In the report he writes: \"\"The company will beat analysts’ earnings projections next month.\"\" Vasilis first shares the recommendation with all clients by email. He then calls each of his clients by phone to present the recommendation. Has Vasilis violated the Standards?\",\"No\",\"Yes, by calling each of his clients by phone to present the recommendation\",\"Yes, by writing in the report, \"\"The company will beat analysts’ earnings projections next month”\",\"C\",\"C. Correct because according to Standard V (B), Communication with Clients and Prospective Clients, opinion be separated from fact. Violations often occur when reports fail to separate the past from the future by not indicating that earnings estimates, changes in the outlook for dividends, or future market price information are opinions subject to future circumstances. In this case, the statement was referring to future outcome which may or may not turn out to be true, thus a violation.\"\n\"ETH\",\"Melissa Kon, CFA, is an equity analyst. She recently left her job at Hamm Capital (HC) to join Eagle Investments (EI). Kon obtains the express consent of HC to take one of her historical research reports with her. At EI, she diligently updates and publishes the report. Afterwards, she re-creates supporting records from memory for record keeping purposes. Has Kon violated the Standards?\",\"No.\",\"Yes, by publishing the updated research report.\",\"Yes, by re-creating supporting records from memory.\",\"C\",\"C. Correct because according to Standard V (C), Record Retention, a member must not re-create supporting records from memory. Standard V(C), Record Retention, states The member or candidate cannot use historical recommendations or research reports created at the previous firm because the supporting documentation is unavailable. For future use, the member or candidate must re-create the supporting records at the new firm with information gathered through public sources or directly from the covere\"\n\"ETH\",\"Which of the following individuals can refer to themselves as a candidate in the CFA Program? Individual 1 Has passed Level Il and expects to register for Level II in a couple of months Individual 2 Has failed Level I and expects to retake the exam in its next administration Individual 3 Is awaiting results of the Level III exam\",\"Individual 1\",\"Individual 2\",\"Individual\",\"C\",\"C. Correct because according to Standard VII(B), Reference to CFA Institute, the CFA Designation, and the CFA Program, a person is a candidate in the CFA Program if the registered person has sat for a specified examination but exam results have not yet been received.\"\n\"ETH\",\"According to the GIPS standards, a firm:\",\"must include non-discretionary portfolios in the firm's composites.\",\"may refer to its performance calculation methodology as being \"\"in accordance with\",\"GIPS standards.\"\" C. may determine a portfolio is non-discretionary if client imposed restrictions interfere with the implementation of the intended strategy.\",\"C\",\"C. Correct because according to the fundamentals of compliance of the GIPS standards, If documented client-imposed restrictions interfere with the implementation of the intended strategy to the extent that the portfolio is no longer representative of the strategy, the firm may determine that the portfolio is non-discretionary. 140\"\n\"ETH\",\"Hugh Matthew, CFA, covers several companies within a sector. After thorough analysis of each company, he issues \"\"buy\"\" recommendations for each company. In each report, Matthew discloses the assumptions, methodology and risk factors used in his research. Two weeks later, an unexpected event occurs that negatively impacts the sector. Asa result, all the companies Matthew covers experience significant losses. Has Matthew most likely violated the Standards? 96\",\"No\",\"Yes, the Standard relating to diligence and reasonable basis\",\"Yes, the Standard relating to communication with clients and prospective clients\",\"A\",\"A. Correct because according to Standard V (B), Investment Analysis, Recommendations, and Actions - Communication with Clients and Prospective Clients, Members and candidates cannot be expected to disclose risks they are unaware of at the time recommendations or investment actions are made. In assessing compliance with Standard V(B), it is important to establish knowledge of a purported significant risk or limitation. A one-time investment loss that occurs after the disclosure does not constitut\"\n\"ETH\",\"Which of the following statements is most accurate? In countries where regulations conflict with, or contradict, the GIPS standards, firms that claim compliance are required to comply with:\",\"local regulations with full disclosure of the conflict.\",\"the stricter of local regulations or the GIPS standards.\",\"local regulations with optional disclosure of the conflict.\",\"A\",\"A. Correct because according to the GIPS standards, in cases in which laws and/or regulations conflict with the GIPS standards, firms are required to comply with the laws and regulations and make full disclosure of the conflict in the GIPS Report.\"\n\"ETH\",\"Which of the following is a recommended procedure for complying with the Standard relating to preservation of confidentiality? Procedurel Disclose to authorized fellow employees only information that will improve service to the client Procedure2 Encourage the adoption of standard confidentiality procedures utilized by leading firms in the industry\",\"Procedure 1 only\",\"Procedure 2 only\",\"Both Procedure 1 and Procedure 2\",\"A\",\"A. Correct because according to the recommended procedures for compliance with Standard II (E), Preservation of Confidentiality, avoid disclosing any information received from a client except to authorized fellow employees who are also working for the client. Is the information background material that, if disclosed, will enable the member or candidate to improve service to the client?\"\n\"ETH\",\"Tim Howley, CFA, “pumps up” the price of a security by spreading misleading information and later “dumps” the security after the price reaches an artificially high level. Howley has most likely violated the Standard relating to:\",\"market manipulation.\",\"independence and objectivity.\",\"material nonpublic information.\",\"A\",\"A. Correct because according to the Standard 11(B), market manipulation includes (1) the dissemination of false or misleading information. Also, information-based manipulation includes, but is not limited to, spreading false rumors to induce trading by others. For example, members and candidates must refrain from “pumping up” the price of an investment by issuing misleading positive information or overly optimistic projections of a security's worth only to later “dump” the investment (i.e., sell\"\n\"ETH\",\"A member manages two fee-paying family accounts at her firm, The member has the power to vote on the shares held in Account 1 and the discretion to sell shares held in Account 2. According to the Standards, is the member considered a beneficial owner of the shares held in her family accounts?\",\"No\",\"Yes, for Account 1 only\",\"Yes, for both Account 1 and Account 2\",\"C\",\"C. Correct because for the purposzs of Standard VI(A) Disclosure of Conflicts, members and candidates beneficially own securities or other investments if they have a direct or indirect pecuniary interest in the securities, have the power to vote or direct the voting of the shares of the securities or investments, or have the power to dispose or direct the disposition of the security or investment. Therefore, the member is considered a beneficial owner for shares held in both Account 1 and Accoun\"\n\"ETH\",\"Shirin Regali, CFA, is a well-respected, sell-side analyst covering the biotech sector. While researching the market prospects for a drug being trialed by BioHeal Inc., Regali interviews industry experts who are not affiliated with the trials or BioHeal. These experts express confidence that the drug will pass the trials and be a market success. After thorough analysis and based on these experts’ insights, Regali issues a \"\"buy\"\" recommendation for BioHeal and distributes it to her clients and not to the public. Has Regali most likely violated the Standard relating to material nonpublic information?\",\"No\",\"Yes, by distributing the recommendation to her clients and not to the public\",\"Yes, by issuing a \"\"buy\"\" recommendation for BioHeal based on insights from industry experts\",\"A\",\"A. Correct because Regali did not violate Standard II (A), Nonpublic Material Information. The Standards permit the use of industry experts. Members and candidates may provide compensation to individuals [industry experts] for their insights without violating this standard. In this case, the industry experts are unaffiliated with the trials and thus do not have access to inside information on the trials, so their insights can be used to make investment decisions. The Standards also permit the se\"\n\"ETH\",\"David Andrews, CFA, is an investment manager with Aldona Investments. Aldona secures a block of stock in an oversubscribed initial public offering. Andrews decides to prorate the issue to all fee-paying accounts for which it is appropriate, including the fee-paying accounts of his immediate family members. Has Andrews violated the Standard relating to fair dealing?\",\"No.\",\"Yes, by prorating the issue to all subscribers.\",\"Yes, by including immediate family members in the transaction.\",\"A\",\"A. Correct because Standard III (B), Fair Dealing, states that if the issue is oversubscribed, then the issue should be prorated to all subscribers. In addition, if the investment professional’s family-member accounts are managed similarly to the accountsof other clients of the firm, however, the family-member accounts should not be excludedfrom buying such shares.\"\n\"ETH\",\"‘Which of the following most likely violates the Standard relating to preservation of confidentiality?\",\"Recommending a former client as a potential donor for a local charity\",\"Disclosing details of client activity to the CFA Institute Professional Conduct\",\"Program C. Providing confidential information about a prospective client when permitted by the prospective client\",\"A\",\"A. Correctbecause Standard III (E), Preservation of Confidentiality, requires Members and Candidates must keep information about current, former, and prospective clients confidential. Also, this standard protects the confidentiality of client information even if the person or entity is no longer a client of the member or candidate.\"\n\"ETH\",\"Which statement regarding market manipulation is consistent with theStandards? Members must refrain from:\",\"inducing trading by disseminating verifiable information.\",\"engaging in practices which exploit perceived market inefficiencies.\",\"securing a dominant position in a financial instrument to exploit the price of the underlying asset.\",\"C\",\"C. Correctbecause Standard II(B), Market Manipulation, prohibits such activity. Transaction-based manipulation includes, but is not limited to securing a controlling, dominant position in a financial instrument to exploit the price of the underlying asset. 159\"\n\"ETH\",\"The Standard relating to disclosure of conflicts requires a member to:\",\"avoid all actual and potential conflicts of interest.\",\"treat all clients equally when disseminating investment recommendations or taking\",\"investment action. C. provide clients and prospective clients with information needed to evaluate the objectivity of investment advice given by the member.\",\"C\",\"{c} Correct because Standard VI(A), Disclosure of Conflicts requires members and candidates to make full and fair disclosure of all matters that could reasonably be expected to impair their independence and objectivity or interfere with respective duties to their clients, prospective clients, and employer and protects investors and employers by requiring members and candidates to fully disclose to clients, potential clients, and employers all actual and potential conflicts of interest. Once a me\"\n\"ETH\",\"Jan Loots, CFA, quit his job as a portfolio manager at an investment firm with which he had a non-solicitation agreement he signed several years ago. Loots received permission to takehis investment performance history with him and also took a copy of the firm's software- trading platform. Subsequently, Loots sent out messages on social media sites announcing he ‘was looking for clients for his new investment management firm. Access to Loots’ social media sites is restricted to friends, family, and former clients. Loots least likely violated the CFA Institute Standards of Professional Conduct concerning his:\",\"trading software.\",\"non-solicitation agreement.\",\"investment performance history.\",\"C\",\"C. Correct because the portfolio manager received permission to use his investment performance history from his prior employer. The member violated his non-solicitation agreement by indicating his availability to new clients on several social media sites accessible by clients of his former employer. This is a violation of Standard IV(A)-Loyalty because he did not act for the benefit of his former employer. In this case, the member may cause harm to his former employer if his weekend messages res\"\n\"ETH\",\"According to the Standard related to independence and objectivity, a member must:\",\"refuse all business-related gifts.\",\"adhere to strict standards of conduct that govern how issuer-paid research is\",\"conducted. C. pay for transportation, hotel and meal expenses when attending meetings at an issuer's headquarters.\",\"B\",\"B. Correctbecause this is a requirement of Standard I(B), Independence and Objectivity. Issuer-paid research conducted by independent analysts, however, is fraught with potential conflicts. Members must adhere to strict standards of conduct that govern how the research is to be conducted and what disclosures must be made in the report. Analysts must engage in thorough, independent, and unbiased analysis and must fully disclose potential conflicts of interest, including the nature of their compen\"\n\"ETH\",\"A member most likely violates the Standard relating to knowledge of the law if she fails to:\",\"dissociate from unethical conduct.\",\"report illegal activity to the appropriate regulatory organization.\",\"have detailed knowledge of all the laws potentially governing her professional activities.\",\"A\",\"A. Correctbecause under Standard (A), Knowledge of the Law, members and candidates have a responsibility to step away and dissociate from the [unethical] activity. Inaction combined with continuing association with those involved in illegal or unethical conduct may be construed as participation or assistance in the illegal or unethical conduct.\"\n\"ETH\",\"Rita Melmo, CFA, is an analyst at a Greensky Investment (GI). On weekends, she works as a paid employee of a local charity where she negotiates purchase agreements. Melmo does not disclose the charity employment to GI. Melmo is asked to purchase a new truck for the charity and she negotiates a purchase agreement with a local truck dealership. In the purchase agreement, the charity is charged $500 more than the truck's normal sale price. In return, Melmo receives retail vouchers worth $500 from the dealership for her private use. Melmo has most likely violated the Standards:\",\"only by failing to disclose the charity employment to GI.\",\"only by negotiating a purchase agreement in which the charity is charged more than\",\"truck's normal sale price. C. both by failing to disclose the charity employment to GI and by negotiating a purchase agreement in which the charity is charged more than the truck's normal sale price.\",\"B\",\"B. Correctbecause according to Standard I (D), Misconduct, Members and Candidates must not engage in any professional conduct involving dishonesty, fraud, or deceit or commit any act that reflects adversely on their professional reputation, integrity, or competence. Overcharging the charity by any amount is fraud and reflects adversely on Melmo as an investment professional and potentially on her employer and and the investment profession.\"\n\"ETH\",\"In the absence of regulatory guidance or firm policies, CFA Institute recommends maintaining records for at least:\",\"three years.\",\"five years.\",\"seven years.\",\"C\",\"C. Correct because according to Standard V (C), Investment Analysis, Recommendations, and Actions - Record Retention, Local regulators often impose requirements on members, candidates, and their firms related to record retention that must be followed. Firms may also implement policies detailing the applicable time frame for retaining research and client communication records. Fulfilling such regulatory and firm requirements satisfies the requirements of Standard V(C). In the absence of regulator\"\n\"ETH\",\"‘Which of the following statements describe the key concepts of the GIPS standards? Statement1 The GIPS standards are ethical standards to ensure full disclosure of investment performance. Statement2 The GIPS standards require firms to maintain composites for all strategies for ‘which the firm manages discretionary and nondiscretionary accounts. Statement3 The GIPS standards address all aspects of performance measurement.\",\"Statement 1\",\"Statement 2\",\"Statement 3 114 Ethical and Professional Standards: Practice Pack- Answers\",\"A\",\"A. Correct. GIPS standards are ethical standards for investment performance presentation to ensure fair representation and full disclosure of investment performance.So, Statement 1 is a key concept of the GIPS standards.\"\n\"FI\",\"If an issuer is required to retire a specified portion of the bond's principal each year, the bond most likely:\",\"is callable.\",\"is a step-up note.\",\"has a sinking fund provision.\",\"C\",\"[8 Correct. A sinking fund provision requires retirement of a portion of the bond's principal every year, rather than retirement of the entire issue at maturity\"\n\"FI\",\"Abond priced at 99.4 hasa modified duration of 6.9 and an annual convexity statistic of ~ 212. If the market yield increases by 75 basis points, the price of this bond is closest to\",\"93.7.\",\"94.3.\",\"94.9.\",\"A\",\"A. Correct because %APVi = (-~AnnModDur x AYield) + [(0.5 x AnnConvexity x A(Yield):)= (-6.9 * 0.0075) + (0.5 x -212 x 0.00757) =-0.05175 - 0.0059625 = 0.0577125, rounded to 5.77%. The percentage decline in price =-0.0577125 x 99.4 = -5.7366, and the bond price = 99.4 - 5.7366 = 93.6634, rounded to 93.66.\"\n\"FI\",\"If interest rates rise over the holding period, the total return of a coupon bond held until maturity is most likely to be:\",\"less than the yield to maturity at purchase.\",\"equal to the yield to maturity at purchase.\",\"greater than the yield to maturity at purchase.\",\"C\",\"{8 Correct because a long-term investor faces coupon reinvestment risk as well as market price risk if the bond needs to be sold prior to maturity. An [buy-and-hold] investor [in a 10-year bond] with a 10-year time horizon is concerned only with coupon reinvestment risk. This situation assumes, of course, that the issuer makes all of the coupon and principal payments as scheduled. The buy-and-hold investor has a higher total return if interest rates rise and a lower total return if rates fall,\"\n\"FI\",\"In a securitization, the purchase agreement between the seller of the collateral and the special purpose entity most likely provides:\",\"a description of the transaction structure.\",\"representations about the quality of the assets.\",\"documentation of enhancements used to reduce credit risk.\",\"B\",\"B. Correct because an important legal document is the purchase agreement between the seller of the collateral and the SPE, which sets forth the representations and warranties that the seller makes about the assets sold, These representations and warranties assure investors about the quality of the assets.\"\n\"FI\",\"An analyst gathers the following information about a bond: Price 96.00 Price with yield to maturity 10 basis points higher 95.80 Price with yield to maturity 10 basis points lower 96.30 The approximate convexity of this bond is closest to\",\"521.\",\"1,042.\",\"2,604.\",\"B\",\"B. Correctbecause ApproxCon= 4¥d*(P%) Therefore the approximate [56.3+95.8) [2x96] convexity of this bond = (0.000%x(38) = 1,042,\"\n\"FI\",\"An analyst gathers the following information about a company that only has senior unsecured debt: Type Total Amount Outstanding Time to Maturity Floating-rate note (FRN) $50 million 12 years Fixed-rate bond $10 million 2 years In a bankruptcy scenario, if the priority of claims is enforced, it is most likely that:\",\"fixed-rate bond is repaid first because it matures earlier.\",\"both bondholders are repaid proportionally to the amount owed.\",\"FRN is repaid first because it has the highest amount outstanding.\",\"B\",\"B. Correct because both bonds represent forms of senior unsecured debt and therefore, all creditors are at the same level of the capital structure and treated as one class; thus, a senior unsecured bondholder whose debt is due in 30 years has the same pro rata claim in bankruptcy as one whose debt matures in six months. This provision is referred to as bonds ranking pari passu (‘on an equal footing’) in right of payment.\"\n\"FI\",\"An analyst is concerned that a bond might be downgraded one category by Standard & Poor's and become non-investment grade. The current rating of this bond is most likely:\",\"A-.\",\"BB-.\",\"BBB-.\",\"C\",\"C. Correct because BBB- is the lowest rating for investment grade bonds. A one- category downgrade (from BBB- to BB-) would make the bond non-investment grade.\"\n\"FI\",\"A corporation with a holding company structure has debt at both its parent holding company and operating subsidiaries. Debt at the operating level must be serviced before funds can be upstreamed to pay debt at the holding company. This arrangement best describes:\",\"structural subordination.\",\"a cross-default provision.\",\"the corporate family rating.\",\"A\",\"A. Correct because another factor considered by rating agencies is structural subordination, which can arise when a corporation with a holding company structure has debt at both its parent holding company and operating subsidiaries. Debt at the operating subsidiaries will get serviced by the cash flow and assets of the subsidiaries before funds can be passed (“upstreamed”) to the holding company to service debt at that level.\"\n\"FI\",\"The current yield for a 4.5% coupon, 10-year bond, with a maturity par value of $100 and currently priced at $85.70 is closest to:\",\"4.50%.\",\"5.25%.\",\"5.93%.\",\"B\",\"B Correctbecause current yield is calculated as (§4.5/$85.70) = 5.25%.\"\n\"FI\",\"An analyst gathers the following information about a 6% coupon bond currently trading at par: Benchmark RatePrice per 100 of Par Value 5.9% 100.75 6.0% 100.00 6.1% 99.26 The bond's effective duration is closest to\",\"3.75.\",\"7.45.\",\"7.50.\",\"B\",\"B. Correct because effective duration = (PV. PV.) / (2 x Acurve x PV.) = (100.75 - 99.26) / (2 x 0.001 x 100.00) = 7.45.\"\n\"FI\",\"An analyst gathers the following information about a pension plan's liabilities: I R r Value of Liabiliti $ Millions) 0.5% 198 1.0% 186 1.5% 174 Ifinterest rates are currently 1.0%, the effective duration of the liabilities is closest to\",\"6.5.\",\"12.9.\",\"25.8.\",\"B\",\"B. Correct because effective duration = (PV. ~ PV.)/(2 x ACurve PV) = ($198 million - $174 million) /(2 x 0.005 x $186 million) = 12.9032 = 12.9,\"\n\"FI\",\"Which of the following is a curve duration measure?\",\"A, Modified duration\",\"Effective duration\",\"Macaulay duration\",\"B\",\"B. Correct because effective duration is a curve duration statistic in that it measures interest rate risk in terms of a parallel shift in the benchmark yield curve.\"\n\"FI\",\"Bonds issued in the Eurobond market are most likely:\",\"denominated only in euros.\",\"in the form of registered bonds.\",\"(-) issued within the jurisdiction of the issuer's home country.\",\"B\",\"B. Correct because Eurobonds, domestic, and foreign bonds are now registered bonds for which ownership is recorded by either name or serial number.\"\n\"FI\",\"All else being equal, expected loss for a debt instrument:\",\"is independent of the recovery rate,\",\"decreases as the recovery rate increases.\",\"changes proportionally to the recovery rate.\",\"B\",\"B. Correct because Expected loss = Default probability x Loss severity given default, ‘where loss severity is often expressed as (1 ~ Recovery rate), where the recovery rate isthe percentage of the principal amount recovered in the event of default. Thus expected loss can also be written as Expected loss = Default probability x (1 - Recovery rate), which means that the higher the recovery rate, the lower the expected loss.\"\n\"FI\",\"For a bond with an embedded option, effective duration is the most appropriate measure of interest rate risk because the bond's:\",\"future cash flows are uncertain.\",\"internal rate of return is well-defined.\",\"pricing is sensitive to changes in credit spreads.\",\"A\",\"A. Correct because effective duration is essential to the measurement of the interest rate risk of a complex bond, such as a bond that contains an embedded call option. The problem is that future cash flows are uncertain because they are contingent on future interest rates. The issuer's decision to call the bond depends on the ability to refinance the debt ata lower cost of funds. Effective duration is the appropriate duration measure,\"\n\"FI\",\"An analyst gathers the following information about a spot curve: Term to MaturitySpot Rate 1year 6% 2 years 5% 3 years 4% If the coupon rate of a 3-year annual-pay bond is 4%, the price of the bond is closest to\",\"97.28.\",\"99.86.\",\"100.00.\",\"B\",\"B. Correct because given the spot rates, the price ofa bond can be calculated using the following formula: PV = [PMT/(1 + Zi): + PMT/(1 + Z): + ct (PMT + FV)/(1 + Z.)4] Hence, PV =4/(1 + 0.06) + 4/(1 + 0.05) + (4 + 100)/(1 + 0.04): = 4/1.06 + 4/1.1025 + 104/1.1249 = 3.77358+ 3.62812 + 92.4556 = 99.8573 ~ 99.86.\"\n\"FI\",\"An analyst gathers the following information about three option-free bonds: —— Bond1Bond 2Bond3 Coupon rate 5% 3% 3% Maturity (years) 15 10 15 All else being equal, if the market discount rate decreases by 50 basis points, the bond most likely to experience the greatest percentage price change is:\",\"Bond 1.\",\"Bond 2.\",\"Bond 3.\",\"C\",\"C. Correct because for the same time-to-maturi ty, a lower-coupon bond has a greater percentage price change than a higher-coupon bond when their market discount rates change by the same amount (the coupon effect). Bond 3 has the same time-to-maturity as Bond 1 but a lower coupon, thus Bond 3 would experience a greater percentage price change compared to Bond 1. Also, generally, for the same coupon rate, a longer-term bond has a greater percentage price change than a shorter-term bond when their\"\n\"FI\",\"Implied forward rates are best defined as the:\",\"geometric average of spot rates.\",\"breakeven reinvestment rates between zero-coupon bonds.\",\"current yield to maturity on zero-coupon bonds of different maturities.\",\"B\",\"B. Correct because implied forward rates (also known as forward yields) are calculated from spot rates, An implied forward rate is a break-even reinvestment rate. When the market is in equilibrium (no arbitrage) the implied forward rate is the sameas the forward rate.\"\n\"FI\",\"Tightening corporate bond yield spreads are most likely associated with:\",\"issuers’ deteriorating creditworthiness.\",\"periods of high demand for corporate bonds.\",\"broker-dealers’ reduced ability and willingness to make markets.\",\"B\",\"B. Correct because in periods of high demand for bonds, spreads will move tighter.\"\n\"FI\",\"With respect to a bond with an embedded option, for parallel shifts in the benchmark yield curve, effective duration most likely indicates the same interest rate sensitivity as:\",\"key rate durations.\",\"modified duration.\",\"Macaulay duration.\",\"A\",\"A. Correct because for parallel shifts in the benchmark yield curve, key rate durations will indicate the same interest rate sensitivity as effective duration.\"\n\"FI\",\"The price value of a basis point (PVBP) for a bond with a full price of 103.50 and a modified duration of 6.2 is closest to:\",\"0.0642.\",\"0.6420.\",\"6.4200.\",\"A\",\"A. Correct because modified duration provides anestimate of the percentage price change for a bond given a change in its yield-to-maturity: %APV = —AnnModDur x AYield. Also, another version of money duration is the price value of a basis point (PVBP) for the bond. The PVBP is an estimate of the change in the full price given a 1 bp change in the yield-to-maturity. Here: -£.2 x 0.0001 = 0.00062 and PVBP = 0.00062 x 103.50 = 0.06417, rounded to 0.0642.\"\n\"FI\",\"An analyst gathers the following details about a bond portfolio: 1 95 730 2 120 515 If each bond has a par value of £25 million, the modified duration of this bond portfolios closest to:\",\"5.8.\",\"6.1.\",\"6.2.\",\"A\",\"A. Correct because money duration (MoneyDur) is calculated as the annual modified duration times the full price (PV) of the bond, including accrued interest. Thus the modified durations of the bonds are 730/95 = 7.6842 and 515/120 = 4.29167, respectively. The modified duration of a bond portfolio is calculated as the weighted average of the statistics for the individual bonds. The shares of overall portfolio market value are the weights. Here, the market values of the bonds are £25 million * 95/\"\n\"FI\",\"An analyst observes the following yields to maturity on zero-coupon government bonds: M Yield to Maturi 1lyear 1.5% 2years 2.5% 3years 3.5% The 2yly implied forward rate is closest to:\",\"4.5%.\",\"5.5%.\",\"6.6%.\",\"B\",\"B. Correct because the 2yly yield is the implied one-year forward yield two years from now. The 2y1y implied yield can be found using (1 + z)z x (A +IFRu)i=(1+2)2= (1+ 0.025): x (1+ IFRu)+ = (1 + 1.035). [FRx = (1 + 1.035): / (1 + 0.025): - 1 = 1.1087 / 1.0506 -1=0.0553 = 5.53%,\"\n\"FI\",\"Compared to an otherwise similar option-free bond, investors require a higher yield for a corporate bond with\",\"put provision.\",\"call provision.\",\"conversion provision.\",\"B\",\"B. Correct because the call provision is a valuable option for the issuer. Thus, other things equal, investors require a higher yield (and thus pay a lower price) for a callable bond than for an otherwise similar non-callable bond.\"\n\"FI\",\"The price of a bond issued in the United Kingdom by a US-based company and denominated In British pounds most likely changes when:\",\"US interest rates change only.\",\"British interest rates change only.\",\"both US and British interest rates change.\",\"B\",\"B. Correct because the currency denomination of a bond's cash flows influences which country’s interest rates affect a bond's price. The price of a bond issued by a US- based company and denominated in British pounds will be affected by British interest rates.\"\n\"FI\",\"A floating-rate note makes semiannual interest payments and has a coupon rate equal to the six-month market reference rate plus 45 basis points. The interest payments are made in June and December. If the six-month market reference rate was 1.95% in June and 2.25%in December of the same year, the coupon rate paid in December of that year was closest to\",\"2.40%.\",\"2.55%.\",\"2.70%.\",\"A\",\"A Correct because the applicable interest rate in December is the six-month market reference rate in June plus the 45 basis point margin = 1.95% + 0.45% = 2.40%.\"\n\"FI\",\"An analyst gathers the following information about a bond: Par value 100 Coupon rate 5.50% Coupon frequency Annual Time to maturity ~~ 5 years Holding period 3 years If the market discount rate is 4.75% for the holding period, the future value of reinvested coupons at the end of the holding period is closest to:\",\"15.05.\",\"17.30.\",\"18.12.\",\"B\",\"B. Correct because the first coupon is reinvested at 4.75% for two years, the second coupon is reinvested at 4.75% for one year, and the third coupon has not yet been reinvested. (5.50 x 1.047572) + (5.50 x 1.0475) + 5.50 = 17.2962 = 17.30. Interest rates are the rates at which coupon payments are reinvested and the market discount rates at the time of purchase and at the time of sale if the bond is not held to maturity.\"\n\"FI\",\"An investor determines the following information about the price sensitivity of an option- free bond: Rate Change Price 75 basis point increase 104.0 75 basis point decrease 108.5 If the current price is 106, the duration of this bond is closest to\",\"2.1.\",\"2.8.\",\"3.0.\",\"B\",\"B. Correct because the following formula estimates the approximate percentage price change for a 100 basis point change in yield (duration) is: Duration = Price if viel cli x e il 1d ri; 2 x (initial price) x (change in yield in decimal format) =108.5-104 2x106 x 0.0075 =45 1.59 =2.83,0r2.8\"\n\"FI\",\"The number of common shares a convertible bond can be converted into is the:\",\"conversion ratio.\",\"conversion price.\",\"conversion value.\",\"A\",\"A Correct because the conversion ratio is the number of common shares that each bond can be converted into.\"\n\"FI\",\"A credit card receivable asset-backed security most likely:\",\"faces high prepayment risk.\",\"uses fully-amortizing loans as collateral,\",\"reinvests principal repayments during the lockout period.\",\"C\",\"C. Correct because the collateral of credit card receivable ABS is a pool of non- amortizing loans. These loans have lockout periods during which the cash flows that are paid out to security holders are based only on finance charges collected and fees. When the lockout period is over, the principal that is repaid by the cardholders is no longer reinvested but instead is distributed to investors.\"\n\"FI\",\"An analyst gathers the following spot and forward rates: 2-year spot rate 1.0% 4-year spot rate 2.5% “4-year forward rate, two years from today 3.0% The 2-year forward rate, four years from today is closest to:\",\"2%.\",\"3%.\",\"4%.\",\"A\",\"A Correct because the general formula for the relationship between two spot rates and the implied forward rate is: (1 + 2a x (1 + IFRusa)o4= (1 +20)\"\", where zis the x-year spot rate and IFR. is the y-year forward rate, x years from now. Using the formula, the 6 year spot rate can be calculated in two different ways: 1. Using A=2, B = 6: (1 +2)¢= (1+ 2a)s x (1+ FR) 2. Using A=4, B= 6 (1 +z)e= (1 +2) x (1+ IFRa): Equating the two we get: (1 + 22) % (1 + IFRa)+= (1 +2)0 (1 + IFRy):. Using the numbe\"\n\"FI\",\"Abond issuer has a credit rating of BBB, Based only on this information, the rating of a senior unsecured bond from this issuer is most likely to be:\",\"lower than BBB.\",\"BBB.\",\"higher than BBB.\",\"B\",\"B. Correct because the issuer credit rating usually applies to its senior unsecured debt.\"\n\"FI\",\"An analyst gathers the following information about a zero-coupon bond: Time to maturity 5 years Annual convexity 28.835 Annual yield to maturity 2% If the yield decreases by 1%, the bond's percentage change in price is closest to\",\"4.76%.\",\"5.05%.\",\"5.14%.\",\"B\",\"B. Correct because the Macaulay duration of a zero-coupon bond is its time-to- maturity and modified duration is the Macaulay duration statistic divided by one plus the yield per period. Here, modified duration = 5/1.02 = 4.901961. Thus, the percentage change in price = ~4.901961 * -0.01 + (0.5 * 28.835 * -0.012) =0.04901961 + 0.0014418 = 5.04614%, rounded to 5.05%.\"\n\"FI\",\"An analyst gathers the following information about forward rates: Time Period Forward Rate oyly 1% 1yly 2% 2yly 4% Using only this information, the price per 100 of par value of a 3-year, 1% annual coupon bond is closest to:\",\"84.05.\",\"91.74.\",\"96.23.\",\"C\",\"C. Correct because the geometric average of the forward rates gives us the spot rates (ie. (Oyly x 1yly) = (1 + ZJ2, (Oyly x 1yly x 2yly) = (1 + Z3)?)), hence the price of a bond using forward rates can be calculated using: PV'= PMT / (1 + Z,): + PMT / (A +Ze+ (PMT + FV) / (1 + Zu)x where Z, = Spot rate, or the zero-coupon yield, or zero rate, for\"\n\"FI\",\"An analyst gathers the following information about three option-free bonds, each trading ata premium: Bond1 4% 4% 10 years Bond2 4% 5% 1lyears Bond3 5% 5% 9 years All else being equal, the bond with the lowest Macaulay duration is most likely:\",\"Bond 1.\",\"Bond 2.\",\"Bond 3.\",\"C\",\"C. Correct because the Macaulay and modified duration statistics for a fixed-rate bond depend primarily on the coupon rate, yield-to-maturity, and time-to-maturity. A higher coupon rate or a higher yield-to-maturity reduces the duration measures. A longer time-to- maturity usually leads to a higher duration. It always does so for a bond priced ata premium or at par value.” In this case, Bond 3 has a higher coupon, the same or higher yield-to-maturity, and the shortest time to maturity. It theref\"\n\"FI\",\"An analyst gathers the following information about a bond:< Clean price (per 100 of par value) 114.75 Annual modified duration 4.8250 Macaulay duration (years) 4.9469 Accrued interest (per 100 of parvalue) 1.6250 The bond's money duration (per 100 of par value) is closest to\",\"553.67.\",\"561.51.\",\"575.70.\",\"B\",\"B. Correct because the money duration equals the product of modified duration and full price. Full price = Clean price + Accrued interest = 114.75 + 1.625 = 116.375; Money duration = Modified duration x Full Price = 116.375 x 4.8250 = 561.5094 ~ 561.51. Modified duration is a measure of the percentage price change of a bond given a change in its yield-to-maturity. A related statistic is money duration. The money duration of a bond is a measure of the price change in units of the currency in whic\"\n\"FI\",\"An analyst gathers the following information about a bond that pays interest annually: Coupon rate 4% Time-to-maturity 3 years Par value $100,000 If the market discount rate is 5%, the market value of this bond is closest to\",\"$89,839.\",\"$97,277.\",\"$102,775.\",\"B\",\"B. Correct because the price of the bond is the present value of the promised cash flows and is calculated as follows: Price of bond = 4,000/(1 +5%)* + 4,000/(1+5%)? + 104,000/(1+5%) = 3,809.5238 + 3,628.1179 + 89,839.1102 = 97,276.7520 = 97,277. Calculator inputs: FV = 100,000,1= 0.05, N = 3, PMT = 4,000,PV = 97,276.75 = 97.277.\"\n\"FI\",\"Which of the following mortgage features most likely benefits the lender?\",\"Non-recourse loan\",\"Prepayment option\",\"Prepayment penalty\",\"C\",\"C. Correct because the purpose of the prepayment penalty is to compensate the lender for the difference between the contract rate and the prevailing mortgage rate if the borrower prepays when interest rates decline.\"\n\"FI\",\"With respect to the notching process adopted by credit rating agencies, a corporate’s subordinated debt is most likely:\",\"notched up from the corporates junior subordinated debt.\",\"subject to a smaller notching adjustment the higher the corporate's issuer rating.\",\"notched down from the corporate's issuer rating due to higher probability of default.\",\"B\",\"B. Correct because the rating agencies have adopted a notching process whereby their credit ratings on issues can be moved up or down from the issuer rating, which is usually the rating applied to its senior unsecured debt. As a general rule, the higher the senior unsecured rating, the smaller the notching adjustment.\"\n\"FI\",\"Money market yields are:\",\"annualized and compounded.\",\"stated fora common periodicity.\",\"stated on a simple interest basis.\",\"C\",\"C. Correct because the rate of return on a money market instrument is stated on a simple interest basis. 50\"\n\"FI\",\"A portfolio manager gathers the following information about an option-free bond that washeld to maturity: Realized horizon yield 4.2% Reinvestment rate 41% The yield to maturity at purchase was most likely:\",\"less than 4.2%.\",\"equalto4.2%.\",\"greater than 4.2%.\",\"C\",\"C. Correct because the realized horizon yield matches the original yield-to-maturity if (1) coupon payments are reinvested at the same interest rate as the original yield-to- maturity, and (2) the bond is sold at a price on the constant-yield price trajectory, which implies that the investor does not have any capital gains or losses when the bond is sold. Since the reinvestment rate is less than the horizon yield and the bond is held to maturity, the yield to maturity is greater than the horizon\"\n\"FI\",\"A three-year, semiannual-pay bond with a $100 par value and a 5% coupon rate is purchased for $108. One year later, if the yield to maturity has decreased by 100 basis points, the change in the value of this bond is closest to:\",\"$0.57.\",\"$1.52,\",\"$3.08.\",\"A\",\"A. Correct because the value of a bond is calculated as: PV= [PMT + (1+)] + [PMT +(1+r)] +..+ [(PMT + FV) (141) where: PV = present value, or the price of the bond PMT = coupon payment per. period FV = future value paid at maturity, or the par value of the bond r = market discount rate, or required rate of return per period N = number of evenly spaced periods to maturity Using calculator inputs, N = (3 x 2)=6,PMT = (5% +2) x 100 = $2.5, FV = $100, PV = $108, Solve for 1, is equal to 1.114% semi-\"\n\"FI\",\"For a fixed-rate bond, when interest rates decrease, the future value of reinvested coupon payments most likely:\",\"decreases and the market price of the bond increases.\",\"increases and the market price of the bond decreases.\",\"increases and the market price of the bond increases,\",\"A\",\"A. Correct because there are two offsetting types of interest rate risk that affect the bond investor: coupon reinvestment risk and market price risk. The future value of reinvested coupon payments (and in a portfolio, the principal on bonds that mature before the horizon date) increases when interest rates £80 up and decreases when rates go down. The sale price on a bond that matures after the horizon date (and thus needs to besold) decreases when interest rates £80 up and increases when rates \"\n\"FI\",\"Which of the following debt categories has the highest ranking in terms of priority ofpayment?\",\"Second lien debt\",\"Subordinated debt\",\"Senior unsecured debt\",\"A\",\"A. Correct because this is a secured debt and therefore has higher priority than any unsecured debt. In the event of default, unsecured debtholders’ claims rank below (i.e., get paid after) those of secured creditors under what's known as the priority of claims. First lien debt or loan refers to a pledge of certain assets that could include buildings but might also include property and equipment, licenses, patents, brands, and so on. There can also be second lien, or even third lien, secured deb\"\n\"FI\",\"All else being equal, when the market interest rate falls below a bond's coupon rate, potential price appreciation is most limited for\",\"putable bond.\",\"callable bond.\",\"option-free bond.\",\"B\",\"B. Correct because when interest rates are low, the effective duration of the callable bond is lower than that of the otherwise comparable non-callable bond because the callable bond price does not increase as much when benchmark yields fall. The presence of the call option limits price appreciation especially when interest rates are falling and the bond is more likely to be called.\"\n\"FI\",\"An investor gathers the following information about an investmentin a bond with a 10- year tenor: 19 Purchase price 95.27 Sale price 102.06 Sum of reinvested coupon payments 24.28 If the holding period was seven years, the horizon yield is closest to\",\"2.29%.\",\"2.86%.\",\"4.11%.\",\"C\",\"€. Correct because a horizon yield is the internal rate of return between the total return (the sum of reinvested coupon payments and the sale price or redemption amount) and the purchase price of the bond. The horizon yield on a bond investment is the annualized holding-period rate of return. 95.27 = (102.06 + 24.28) / (1 + 1)\"\"7 => 1 = 0.041147 ~ 4.11%. Calculator solution: N = 7; PV = -95.27; FV = 102.06 + 24.28; CPT 1/Y = 411%.\"\n\"FI\",\"Abond has the following characteristics: Time to maturity 3 years Coupon rate 12% Payment period Semiannual For ayield to maturity of 4%, the price of the bond per 100 of par value is closest to\",\"122.20.\",\"122.41.\",\"122.53. 20 Fixed Income: Practice Pack- Answers\",\"B\",\"B. Correct because [3 3 3 5 6 64100 PV L1+002)* + (1+0.02)* + (1+0.02)* + (140.02)* + (140.02) + (140.02) =122.4057 ® 122.41\"\n\"FSA\",\"Which of the following companies would most likely be considered to have the lowest financial reporting quality, other things equal? A. A company that provides high quality, decision-useful information under GAAP but\",\"delays its reports.\",\"A company that reports significant profits due to a favorable exchange rate\",\"movement. (oh A company that reports the results from two different segments as a combined entity.\",\"C\",\"C. Correct. Combining the results from two segments is an example of biased reporting, which falls in the middle of the quality spectrum. It is difficult to interpret the profitability of each segment when their results are combined.\"\n\"FSA\",\"Which of the following is lowest in quality on the spectrum of GAAP conforming financial reports?\",\"Aggressive accounting choices\",\"Earnings management\",\"Conservative accounting choices\",\"B\",\"B. Correct. Earnings management represents deliberate actions to influence reported earnings and their interpretation. The distinction between earnings management and biased choices is subtle and, primarily, a matter of intent.\"\n\"FSA\",\"An analyst would most likely conduct additional analysis when faced with which of the following financial presentations?\",\"A non-GAAP financial measure that excludes an expense that is likely to recur\",\"Reporting a non-GAAP financial measure in an SEC filing\",\"A change from LIFO inventory accounting to FIFO\",\"A\",\"A. Correct. The exclusion of recurring items from non-GAAP financial measures is strictly prohibited by the SEC and should raise concerns that additional analysis is needed.\"\n\"FSA\",\"Under International Financial Reporting Standards (IFRS), reported operating cash flowsare most likely to be increased by the classification choice made for:\",\"impairment losses on fixed assets.\",\"dividends paid.\",\"interest expense.\",\"C\",\"C. Correct. IFRS allows the classification of interest expense as either an operating or a financing cash flow. When interest expense is shown as a financing cash flow, reported operating cash flows are higher.\"\n\"FSA\",\"Which of the following conditions conducive to issuing low-quality financial reports is most likely a result of poor internal controls?\",\"Rationalization\",\"Opportunity\",\"Motivation\",\"B\",\"B. Correct. Poor internal controls provide opportunities for errors or fraud to be incorporated in financial reporting without being detected.\"\n\"FSA\",\"An analyst gathers the following information (in € millions) relating to a company's merchandise inventory as of 31 December of Year 1: Cost 65 Net realizable value 60 Current replacement cost 58 On 31 December of Year 2, the net realizable value of the inventory is €7 million higher than its carrying value. Under US GAAP, the amount (in € millions) of the reversal of the prior write-down is:\",\"0.\",\"5.\",\"7.\",\"A\",\"A. Correct as U.S. GAAP prohibit the reversal of write-downs.\"\n\"FSA\",\"Compared to the industry average, which of the following financial ratios most likely indicates a company has a highly efficient credit and collection process? A relatively low:\",\"receivables turnover ratio\",\"number of days sales outstanding\",\"number of days of inventory on hand\",\"B\",\"B. Correct because a relatively high receivables turnover ratio (and commensurately low DSO) might indicate highly efficient credit and collection.\"\n\"FSA\",\"An analyst gathers the following information (in € millions) abouta company before any revaluations: Average total assets 20 Average total liabilities 8 Average total equity 12 An initial revaluation increases the carrying value of the asset valued under the revaluation model. Ignoring taxes, the financial leverage ratio most likely:\",\"decreases.\",\"remains the same.\",\"increases.\",\"A\",\"A. Correct because an upward revaluation is treated the same as the amount in excess of the reversal amount. In other words, if a revaluation initially increases the carrying amount of the asset class, the increase in the carrying amount of the asset class bypasses the income statement and goes directly to equity under the heading of revaluation surplus. The financial leverage ratio is the average total assets divided by average total equity. Increasing both the numerator (assets) and denominato\"\n\"FSA\",\"An analyst gathers the following information (in € thousands) abouta company: Net income 143 Gain on sale of equipment 20 Decrease in accounts receivable 38 Cash flow from operating activities (in € thousands) is:\",\"85.\",\"161.\",\"201.\",\"B\",\"B. Correct because changes in working capital accounts include increases and decreases in the current operating asset and liability accounts. To make the ‘working capital 97 adjustments under the indirect method, any increase in a current operating asset account is subtracted from net income and a net decrease is added to net income. When calculating operating cash flow under the indirect method, gain on sale of assets are subtracted from net income. Accordingly, cash flow from operating activit\"\n\"FSA\",\"Under US GAAP and all else being equal, in a period of stable inventory quantities and rising inventory unit costs, which inventory valuation method is least likely to incur inventory write-downs?\",\"FIFO\",\"LIFO\",\"Weighted average cost\",\"B\",\"B. Correct because companies that use specific identification, weighted average cost, or FIFO methods are more likely to incur inventory write-downs than companies that use the LIFO method. Under the LIFO method, the oldest costs are reflected in the inventory carrying amount on the balance sheet. Given increasing inventory costs, the inventory carrying amounts under the LIFO method are already conservatively presented at the oldest and lowest costs. Thus, it is far less likely that inventory wr\"\n\"FSA\",\"An analyst gathers the following information (in € thousands) about a company: Cash flow from operating activities 80 Capital expenditures 15 Interest paid and expensed 10 65 Ifinterest paid is classified as a cash flow from operating activities and the income tax rateis 20%, FCFF (in € thousands) is:\",\"57.\",\"65.\",\"73.\",\"C\",\"C: Correct because FCFF can also be computed from cash flow from operating activities as FCFF = CFO + Int(1 - Tax rate) - FCInv. CFO represents cash flow from operating activities under US GAAP or under IFRS where the company has included interest paid in operating activities. Accordingly, FCFF = CFO + Int(1 - Tax rate) - FCInv; or = 80 + [10 x (1-0.20)] - 15=80+8-15=73, 100\"\n\"FSA\",\"A qualified audit opinion is most likely issued when financial statements are prepared:\",\"in compliance with accounting standards.\",\"with material departures from accounting standards.\",\"with some limitation or exception to accounting standards.\",\"C\",\"C. Correct because financial statements showing “scope limitation or exception to accounting standards” will earn a qualified opinion.\"\n\"FSA\",\"Common-size statements are most likely the output of which of the following phases of the financial statement analysis framework?\",\"Process data\",\"Analyze/interpret the processed data\",\"Develop and communicate conclusions and recommendations\",\"A\",\"A. Correct because common-size statements are an output of the “process data” phase of the financial statement analysis framework.\"\n\"FSA\",\"An analyst gathers the following information about a company's fiscal year ended 31 December: Interest payable on 1 January £45,000 Cash interest paid during the year £15,000 Interest expense during the year ~~ £50,000 Interest payable on 31 December is:\",\"£30,000.\",\"£80,000.\",\"£95,000.\",\"B\",\"B. Correct because Ending interest payable = Beginning interest payable + Interest expense - Cash paid for interest. Accordingly, Ending interest payable = Beginning interest payable + Interest expense - Cash paid for interest = £45,000 + £50,000 £15,000 = £80,000.\"\n\"FSA\",\"Deferred tax assets could arise when:\",\"taxable income exceeds accounting profit.\",\"the carrying amount of assets exceeds their tax base.\",\"accounting income tax expense exceeds income taxes payable.\",\"A\",\"A. Correct because deferred tax assets, which appear on the balance sheet, arise when an excess amount is paid for income taxes (taxable income hi igher than accounting profit).\"\n\"FSA\",\"Ananalyst gathers the following information about a company: ROE 10% Financial leverage ~~ 2.0 Netprofitmargin ~~ 4% EBIT margin 5% Interest burden 85% The total asset turnover ratio is closest to:\",\"1.0.\",\"1.3.\",\"1.5.\",\"B\",\"B. Correct because in accordance to the DuPont analysis for ROE, ROE = Net profit margin x Total asset turnover x Leverage. Thus, Total asset turnover = ROE / (Net profit margin x Leverage); or = 10% / (4% x 2) =125= 1.3.\"\n\"FSA\",\"All else being equal, in a period of stable inventory quantities and declining inventory unit costs, using the LIFO inventory valuation method will result in a lower:\",\"gross profit than if the FIFO inventory valuation method had been used.\",\"current ratio than if the FIFO inventory valuation method had been used.\",\"inventory turnover ratio than if the FIFO inventory valuation method had been used.\",\"C\",\"A. Correct because if purchase prices of inventory are declining, using the LIFO method of inventory valuation will result in a higher ending inventory and a lower cost of sales compared to other inventory valuation methods. Inventory turnover is defined as cost of sales + average inventory. Since cost of sales will be lower under LIFO as compared to FIFO and average inventory will be higher under LIFO as compared to FIFO ina period of declining unit costs, inventory turnover will be lower under\"\n\"FSA\",\"An analyst collects the following information (in € millions) about a manufacturing company’s inventory: Original cost 2,000 68 Net realizable value at end of Year 1 1,700 Net realizable value at end of Year 2 2,500 At the end of Year 2, the balance sheet should reflect inventory (in € millions) of:\",\"1,700.\",\"2,000.\",\"2,500.\",\"B\",\"B. Correct because in each subsequent period, a new assessment of net realisable value is made. Reversal (limited to the amount of the original write-down) is required fora subsequent increase in value of inventory previously written down. Inventory would be 105 written down from 2,000 to 1,700 in Year 1, and the reversal in Year 2 would be limited tothe original write-down of 300, bringing the value back to 2,000 at the end of Year 2,\"\n\"FSA\",\"An analyst gathers the following information (in € thousands) about an electronics manufacturing company's inventory: Cost of ending inventory 3,600 Net realizable value 3,300 Current replacement cost 3,200 Net realizable value less a normal profit margin 3,100 The inventory (in € thousands) is carried on the balance sheet at:\",\"3,100.\",\"3,200.\",\"3,300.\",\"C\",\"C. Correctbecause IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. Accordingly, Min(Cost; Net realizable value) = Min(3,600; 3,300) = 3,300.\"\n\"FSA\",\"Which of the following is an inventory-related financial statement disclosure required under US GAAP?\",\"The carrying amount of inventories carried at fair value less costs to sell.\",\"The circumstances or events that led to the reversal of a prior-year write-down of\",\"inventories. C. The amount of reversal of any prior-year write-down of inventories that is recognized as a reduction in cost of sales in the current period.\",\"A\",\"A. Correct because IFRS require eight financial statement disclosures concerning inventory, including (i) the carrying amount of inventories carried at fair value less costs to sell; (ii) the amount of any reversal of any write-down that is recognised as a reduction in cost of sales in the period; and (iii) the circumstances or events that led to the reversal of a write-down of inventories. Inventory-related disclosures under US GAAP are very similar to the disclosures above, except that require\"\n\"FSA\",\"All else being equal, in a period of declining inventory unit costs and constant inventory quantities, which of the following inventory valuation methods most likely allocates a higher amount of the total cost of goods available for sale to cost of sales on the income statement?\",\"FIFO\",\"LIFO\",\"Weighted average cost\",\"A\",\"A. Correct because in an environment of declining inventory unit costs and constant or increasing inventory quantities, FIFO (in comparison with weighted average cost or LIFO) will allocate a higher amount of the total cost of goods available for sale to cost of sales on the income statement and a lower amount to ending inventory on the balance sheet. Accordingly, because cost of sales will be higher under FIFO, a company's gross profit, or operating profit, and income taxes will be lower.\"\n\"FSA\",\"The adjustments related to changes in the estimated residual value of a long-lived asset should be:\",\"handled prospectively.\",\"shown separately on the income statement.\",\"handled retrospectively unless impractical to do so.\",\"A\",\"A Correct because in contrast to changes in accounting policies (such as whether to expense the cost of employee stock options), companies sometimes make changes in accounting estimates (such as the useful life of a depreciable asset). Changes in accounting estimates are handled prospectively, with the change affecting the financial statements for the period of change and future periods. No adjustments are made to prior statements, and the adjustment is not shown on the face of the income statem\"\n\"FSA\",\"An analyst gathers the following information (in € millions) about a company: —s EBIT 150 Earnings before taxes 130 Net income 110 Total average assets 1,000 ROAis:\",\"11%.\",\"13%.\",\"15%.\",\"A\",\"A. Correct because ROA = Net income / Average total assets; or = 110 /1,000=11%,\"\n\"FSA\",\"An analyst gathers the following information about a company's given fiscal year ended 31 December: Netincome $1,200,000 Number of common shares outstanding on 1 January 1,000,000 Number of common shares issued on 1 April 100,000 Number of common shares outstanding on 31 December 1,100,000 Face value of convertible bonds outstanding for the year $2,000,000 73 Coupon rate on convertible bonds 8% Taxrate 30% If the bonds are convertible into 200,000 common shares and there are no other potentially\",\"dilutive securities outstanding, the company's reported diluted EPS is closest to:A. $1.01.\",\"$1.03.\",\"$1.07.\",\"B\",\"BE. Correct because the basic EPS calculation highlights that the convertible bond is dilutive; that is, Basic EPS = (Net income — Preferred dividends) / (Weighted average number of shares outstanding), Where net income is $1,200,000. There are no preferred dividends. Weighted average number of shares outstanding is: 1,000,000 x (3 months + 12 months) = 250,000 1,100,000 x (9 months + 12 months) = 825,000 Weighted average number of shares outstanding equals 250,000 + 825,000 = 1,075,000 shares. \"\n\"FSA\",\"An analyst gathers the following information about a company: Net profit margin 3.0% Total assetturnover 1.8 Financial leverage 15 Tax burden 0.85 ROE is closest to:\",\"5.4%.\",\"6.9%.\",\"8.1%.\",\"C\",\"C. Correct because ROE = net profit margin x total asset turnover x financial leverage =3.0% x 1.8 x 1.5 = 8.1%.\"\n\"FSA\",\"Under which of the following classifications of leases will a lessor derecognize the leased asset and recognize a lease receivable on the balance sheet at lease inception?\",\"Only a finance lease under IFRS\",\"Only an operating lease under US GAAP\",\"Both a finance lease under IFRS and an operating lease under US GAAP\",\"A\",\"A. Correctbecause the accounting for lessors is substantially identical under IFRS and US GAAP. Under both accounting standards, lessors classify leases as finance or operating leases, which determines the financial reporting. At finance lease inception, the lessor 114 recognizes a lease receivable asset equal to the present value of future lease payments and de-recognizes the leased asset, simultaneously recognizing any difference as a gain or loss.\"\n\"FSA\",\"\"\"A company incurred research costs which were all expensed in the current fiscal year for financial reporting purposes. Applicable tax laws require research costs to be expensed over a 5-year period. If taxable profit will be available against which the deductible temporary differences can be utilized, in the current fiscal year the company will most likely record:\",\"a deferred tax asset.\",\"a deferred tax liability.\",\"neither a deferred tax asset nor a deferred tax liability.\",\"A\",\"A Correct because the carrying amount is zero due to the full amount having been expensed for financial accounting, while the tax base of the asset was only reduced by one- fifth of the total cost in the first year. In addition, taxable profit will be available against which the deductible temporary differences can be utilized. As the asset carrying amount is less than the tax base, it will result in a deferred tax asset.\"\n\"FSA\",\"On the statement of cash flows, interest payments may be classified as a financing cash flow under:\",\"IFRS only.\",\"US GAAP only.\",\"both IFRS and US GAAP.\",\"A\",\"A. Correct because the cash paid for interest is included in operating cash flows under US GAAP and may be included in operating or financing cash flows under IFRS. and US GAAP classify interest expense as an operating activity, even though the principal amount of the debt issued is classified as a financing activity. IFRS allow companies to classify interest expense as either an operating activity or a financing activity.\"\n\"FSA\",\"An analyst gathers the following information (in € thousands) about a company whose fiscal year ends on 31 December: Earnings for the six months ended 30 June of Year 1 2,000 Earnings for the year ended 31 December of Year 1 1,500 Earnings for the six months ended 30 June of Year 2 2,200 The company’s trailing 12 month earnings (in € thousands) for the period ended 30 June of Year 2 is:\",\"1,700.\",\"3,700.\",\"4,200.\",\"A\",\"A. Correct because the company’s trailing 12 months earnings for the period ended 30 June of Year 2 are calculated as (Earnings as of 31 December of Year 1 — Earnings as of 30 June of Year 1) + Earnings as of 30 June of Year 2 = (1.500 ~ 2,000) + 2,200 =-500 + 2,200 =1,700.\"\n\"FSA\",\"Which of the following financial statement disclosures concerning PP&E is required under US GAAP?\",\"The balances of major classes of depreciable assets\",\"The date of revaluation under the revaluation model\",\"A reconciliation of carrying amount at the beginning and end of the period\",\"A\",\"A Correct because the disclosure requirements under US GAAP are less exhaustive. A company must disclose the depreciation expense for the period, the balances of major classes of depreciable assets, accumulated depreciation by major classes or in total, and a general description of the depreciation method(s) used in computing depreciation expense with respect to the major classes of depreciable assets.\"\n\"FSA\",\"A company entered into a 5-year construction contract with a total sales price of £3,000,000. The estimated total costs are £2,000,000 and the company incurred £500,000 actual costs in the first year. The company has extensive experience with similar types of contracts. Costs incurred provide an appropriate measure of progress toward completing the contract. Assuming it is highly probable that revenue will not be subsequently reversed, revenue recognized under the contract in Year 1 is most. likely:\",\"£500,000.\",\"£600,000.\",\"£750,000.\",\"C\",\"C. Correct because the standard states that for performance obligations satisfied over time (e.g, where there is a long-term contract), revenue is recognized over time by measuring progress toward satisfying the obligation. The standard refers to performance obligations satisfied over time and requires that progress toward complete satisfaction of the performance obligation be measured based on input method such as the one illustrated here (recognizing revenue based on the proportion of total co\"\n\"FSA\",\"Which of the following could motivate a lessee to lease a high-value, long-lived asset rather than to purchase it? Lease contracts:\",\"usually require little, if any, down payment.\",\"are reported as off-balance sheet financing structures.\",\"do not require the recognition of a liability on the balance sheet.\",\"A\",\"A Correct because there are several advan: tages to leasing an asset compared with purchasing it: Less cash is needed up front. Leases typically require little, if any, down payment.\"\n\"FSA\",\"For a company reportingon a calendar year basis, the receipt of a payment from a client in Year 1 for the delivery of services in Year 2 most likely increases:\",\"net income for Year 1.\",\"liabilities as of 31 December of Year 1.\",\"cash flow from operating activities for Year 2.\",\"B\",\"B. Correct because there are situations when a company receives cash in advance and actually delivers the product or service later, perhaps over a period of time. In this case, the company would record a liability for unearned revenue when the cash is initially received, and revenue would be recognized as being earned over time as products and services are delivered.\"\n\"FSA\",\"Accounting goodwill arising from acquisitions is:\",\"expensed in the period it arises.\",\"capitalized and amortized over a finite period.\",\"capitalized and tested for impairment annually,\",\"C\",\"C Correct because under both IFRS and US GAAP, accounting goodwill arising from acquisitions is capitalized. Goodwill is not amortised but is tested for impairment annually. If goodwill is deemed to be impaired, an impairment loss is charged against income in the current period.\"\n\"FSA\",\"An analyst gathers the following information (in € thousands) about a company's equipment reported under the cost model: Carrying amount before impairment 2,000 Undiscounted expected future cash flows 1,800 82 Fair value 1,700 Value in use 1,500 Costs to sell 50 The impairment loss (in € thousands) is:\",\"300.\",\"350.\",\"500.\",\"B\",\"B. Correct because under IAS 36, an impairment loss is measured as the excess of carrying amount over the recoverable amount of the asset. The recoverable amount of an asset is defined as the higher of its fair value less costs to sell and its value in use. Value in use is a discounted measure of expected future cash flows. As the recoverable amount = MAX (Fair value less costs to sell, Value in use) = MAX[(1,700 - 50); 1,500] = 1,650, the impairment loss = carrying amount - recoverable amount =\"\n\"FSA\",\"‘Which of the following disclosures is required for each class of PP&E carried under the cost model?\",\"Remaining useful life\",\"Gross carrying amount\",\"Fair value and details of how it was obtained\",\"B\",\"B. Correct because under IFRS, for each class of property, plant, and equipment, a company must disclose the measurement bases, the depreciation method, the useful lives (or, equivalently, the depreciation rate) used, the gross carrying amount and the accumulated depreciation at the beginning and end of the period, and a reconciliation of the carrying amount at the beginning and end of the period. In addition, disclosures of restrictions on title and pledges as security of property, plant, and e\"\n\"FSA\",\"Which of the following components of change in the net pension asset or liability of a defined-benefit pension plan is recognized in other comprehensive income?\",\"Employees’ service costs\",\"Actuarial gains and losses\",\"Net interest expense or income accrued on the beginning net pension asset or liability\",\"B\",\"B. Correct because under IFRS, the change in the net pension asset or liability each period is viewed as having three general components, Two of the components of this change are recognised as pension expense in profit and loss: (1) employees’ service costs,and (2) the net interest expense or income accrued on the beginning net pension asset orliability. The third component of the change in the net pension asset or liability during a period — “remeasurements”— is recognised in other comprehensiv\"\n\"FSA\",\"An analyst gathers the following information about a company: Interest payments $30,000 Capital expenditures $82,000 Net borrowing $18,000 Income tax rate 40% Under U.S. GAAP, free cash flow to equity is most likely:\",\"less than free cash flow to the firm.\",\"equal to free cash flow to the firm.\",\"greater than free cash flow to the firm.\",\"B\",\"B. Correct because under U.S. GAAP, free cash flow to the firm is calculated as CFO + int (1- tax rate) - capital expenditures. Since the firm has interest bearing debt outstanding, $18,000 ($30,000 x (1-4) is added back to CFO in calculating FCFF. In addition, the capital expenditures of $82,000 are subtracted so the equation becomes CFO + $18,000 — $82,000 for a net decrease to CFO of $64,000 ($18,000 - $82,000 =~ $64,000). The calculation for free cash flow to equity is CFO - capital expendit\"\n\"FSA\",\"A manufacturing company reporting under US GAAP using the FIFO inventory valuation method should measure its finished goods’ inventory at the lower of:\",\"cost and market value.\",\"cost and net realizable value.\",\"market value and net realizable value.\",\"B\",\"B. Correct because under US GAAP for fiscal years beginning after December 15, 2016, inventories measured using other than LIFO and retail inventory methods are measured at the lower of cost or net realizable value.\"\n\"FSA\",\"An analyst gathers the following information about a company’s fiscal year ended 31 December: Net income €2,500,000 Weighted average common shares outstanding during the year 2,000,000 Convertible preferred shares outstanding 1,000,000 Dividend per convertible preferred share €1 One convertible preferred share is convertible into two common shares. If the tax rate is 40% and there are no other potentially dilutive securities outstanding, reported diluted EPS is closest to:\",\"€0.38.\",\"€0.48.\",\"€0.63.\",\"C\",\"C. Correct because when a company has convertible preferred stock outstanding, diluted EPS is calculated using the if-converted method. The formula to calculate diluted EPS using the if-converted method for preferred stock is: Diluted EPS = Net income + (Weighted average number of shares outstanding + New common shares that would have been issued at conversion). Therefore, Diluted EPS = €2,500,000 = (2,000,000 + 2 x 1,000,000) = €2,500,000 + 4,000,000 = €0.625 ~ €0.63. However, diluted EPS, by d\"\n\"FSA\",\"An analyst gathers the following information (in £ millions) about a company: EBIT 16 Netincome 8 86 Interest payments 6 Lease payments 4 The fixed charge coverage ratio is closest to:\",\"1.2.\",\"1.6.\",\"2.0.\",\"C\",\"C. Correct because the fixed charge coverage ratio relates fixed financing charges, or obligations, to the cash flow generated by the company. It measures the number of times a company’s earnings (before interest, taxes, and lease payments) can cover the company’s interest and lease payments. Accordingly, Fixed charge coverage ratio = (EBIT + Lease payments) / (Interest payments + Lease payments) = (16 + 4) / (6 + 4) = 2.0. For computing this ratio, an assumption sometimes made is that one-third\"\n\"FSA\",\"A copyright, for which an active market exists, has a set finite life and isused ina company's operations over more than one fiscal period. Under U.S. GAAP, this copyright is reported using:\",\"only the cost model.\",\"only the revaluation model.\",\"either the cost or the revaluation model.\",\"A\",\"A. Correct because, under US GAAP, companies are required to use the cost model to value intangible assets. IFRS allow companies to value intangible assets under a cost model or under a revaluation model. The revaluation model can only be selected when there is an active market for an intangible asset.\"\n\"FSA\",\"Compared to purchasing an asset using debt, leasing an asset is most likely to:\",\"have a higher financing cost.\",\"require a greater down payment.\",\"reduce lessee's exposure to obsolescence.\",\"C\",\"C. Correct because there are several advantages to leasing an asset compared ‘with purchasing it: Convenience and lower risks associated with asset ownership, such as obsolescence. 133\"\n\"AI\",\"The process of representing ownership rights to physical assets on a distributed ledger is referred to as:\",\"tokenization.\",\"initial coin offering.\",\"consensus mechanism.\",\"A\",\"A. Correct because tokenization is the process of representing ownership rights to physical assets on a blockchain or distributed ledger.\"\n\"AI\",\"Hedge funds are most likely to place restrictions on:\",\"redemptions.\",\"the use of leverage.\",\"the use of derivatives. Solution\",\"A\",\"A Correct because alternative investments often have many of the following characteristics. Restrictions on redemptions (i.e., lockups’ and 'gates’). As such, restrictions on redemptions are typically imposed [by hedge funds]. Investors may be required to keep their money in the hedge fund for a minimum period (referred to as a lockup period) before they are allowed to make withdrawals or redeem shares. Investors may be required to give notice of their intent to redeem; the notice period is typi\"\n\"AI\",\"Investors in greenfield infrastructure projects typically:\",\"rely on the assets’ financial and operating history.\",\"invest alongside strategic investors or developers.\",\"have lower development risk than investors in brownfield projects.\",\"B\",\"B. Correctbecause greenfield investors typically invest alongside strategic investors or developers who specialize in developing the underlying assets. 19\"\n\"AI\",\"A joint venture is an alternative investment structure that is most likely used for:\",\"infrastructure investment.\",\"private equity investment.\",\"real estate direct investment.\",\"C\",\"C. Correct because in real estate fund investing, investors may be classified as unit holders, and joint ventures are a partnership structure common in real estate direct investing. 23\"\n\"AI\",\"Regarding distribution methods in alternative investments, which of the following is most advantageous to the limited partners? A(n):\",\"American waterfall.\",\"deal-by-deal waterfall.\",\"whole-of-fund waterfall.\",\"C\",\"C. Correct because in whole-of-fund (European) waterfalls, all distributions go to the LPs as deals are exited and the GP does not participate in any profits until the LPs receive their initial investment and the hurdle rate has been met. In contrast to deal-by-deal (American) waterfalls, whole-of-fund waterfalls occur at the aggregate fund level and are more advantageous to the LPs.\"\n\"AI\",\"Which of the following methods of investing in alternative investments requires the least amount of investment expertise?\",\"Co-investing\",\"Fund investing\",\"Directinvesting\",\"B\",\"B. Correctbecause one of the advantages of fund investing is that it provides access to alternative investments without possessing a high degree of investment expertise.\"\n\"AI\",\"Which of the following statements about private debt is most accurate? Mezzanine debt:\",\"is subordinated to equity in a borrower's capital structure.\",\"is less risky than senior secured debt issued by the same company.\",\"[= may include additional features such as warrants to provide equity participation to lenders.\",\"C\",\"C. Correct because mezzanine debt often comes with additional features, such as warrants or conversion rights, which provide equity participation to lenders/investors, meaning they have the option of converting their debt into equity or purchasing the equity of the underlying borrower under certain circumstances.\"\n\"AI\",\"Which of the following statements about real estate assets is most accurate?\",\"Real estate assets are heterogeneous\",\"Commercial property represents the majority of real estate assets by value\",\"Private real estate has historically had high correlations with other asset classes\",\"A\",\"A. Correct because real estate property has some unique features, including heterogeneity (no two properties are identical) and fixed location.\"\n\"AI\",\"In the private debt market, venture debt:\",\"entails buying the debt of mature companies in financial difficulty.\",\"provides capital to early-stage companies that may be generating little cash flow.\",\"€ entails buying the debt of mature companies in financial difficulty and provides capital to early-stage companies that may be generating little cash flow.\",\"B\",\"B. Correct because this is the definition of venture debt. Venture debt is private debt funding that provides venture capital backing to start-up or early-stage companies that may be generating little or negative cash flow. 31\"\n\"AI\",\"Which of the following real estate investing strategies is most likely to focus on modest redevelopment or upgrades, the leasing of vacant space, and the repositioning of underlying properties to earn a higher return?\",\"Core-plus\",\"Value-add\",\"Opportunistic\",\"B\",\"B. Correct because value-add investments may require modest redevelopment or upgrades, the leasing of vacant space, or repositioning the underlying properties to earn a higher return than core properties.\"\n\"AI\",\"Alternative investments:\",\"include tangible assets only.\",\"include intangible assets only.\",\"may include both tangible and intangible assets.\",\"C\",\"C. Correct because alternative Investments into three categories and several subcategories as follows: 1. Private Capital 2. Real Assets 3. Hedge Funds. Other “real asset” investments may include tangible assets, such as fine wine, art, antique furniture and automobiles, stamps, coins, and other collectibles, and intangible assets, such as patents and litigation actions. 33\"\n\"AI\",\"Which of the following is the most conservative approach to valuing a hedge fund's underlying positions?\",\"Using bid prices for long positions and ask prices for short positions\",\"Usingbid prices for short positions and ask prices for long positions\",\"Using the average of the bid and ask prices for both long and short positions\",\"A\",\"A. Correct because, when market prices or quotes are used for valuation, funds may differ in which price or quote they use (bid price, ask price, average quote, or median quote). A more conservative and accurate approach is to use bid prices for long positions and ask prices for short positions because these are more realistic prices at which the positions could be closed. However, some managers use a simplifying approach whereby they take the average of the bid and the ask; this approach is not\"\n\"AI\",\"All else being equal, which of the following types of private debt is most likely to have the lowest level of risk?\",\"Mezzanine debt\",\"Unitranche debt\",\"Infrastructure debt\",\"C\",\"C. Correct because, as a junior form of subordinated debt, mezzanine private debt offers higher growth potential, equity upside, and higher risk, with the comparatively highest returns. Infrastructure debt is senior and poses the lowest risk, as compared to unitranche debt and mezzanine debt.\"\n\"CI\",\"Which best describes business growth that attracts more customers and merchants, contributing to further growth in the business?\",\"Crowdsourcing\",\"A one-sided network\",\"A multi-sided network\",\"C\",\"C. Correct because as multi-sided (two-sided) networks grow—more users join the service, which attracts more merchants, which in turn attracts more users—these businesses can grow exponentially.\"\n\"CI\",\"‘Which of the following would most likely be included on a company's \"\"financial\"\" balance sheet?\",\"Short-term debt obligations\",\"Relationships with customers\",\"Relationships with key suppliers\",\"A\",\"A Correct because short-term debt is included in a company's financial balance sheet.\"\n\"CI\",\"A company manufacturing and selling a product using someone else's brand name in return for a royalty most likely operates:\",\"under a franchise model.\",\"as a contract manufacturer.\",\"under a licensing arrangement.\",\"C\",\"C. Correctbecause a company will produce a product using someone else’s brand name in return for a royalty under a licensing arrangement.\"\n\"CI\",\"‘When analyzing a company, analysts should:\",\"ignore the company's business model.\",\"develop their own understanding of the company's business model.\",\"rely on management's description of the company's business model.\",\"B\",\"B. Correctbecause a clearly described business model helps the analyst understand a business: how it operates, its strategy, target customers, key partners, prospects, risks, and financial profile. Rather than rely on management's description of its business model, analysts should develop their own understanding.\"\n\"CI\",\"Which of the following is best categorized as a drag on liquidity?\",\"Insufficient credit lines\",\"Uncollected receivables\",\"Early payments to vendors\",\"B\",\"B. Correct because a drag on liquidity is when receipts lag, creating pressure from the decreased available funds. Major drags on receipts involve pressures from credit management and deterioration in other assets and include: Uncollected receivables. The longer these are outstanding, the greater the risk that they will not be collected at all.\"\n\"CI\",\"‘Which of the following combination of factors most likely increases a company's ability to support debt in its capital structure?\",\"High revenue, low cash flow volatility, and a low level of fungible assets\",\"High revenue, low operating leverage, and a high level of fungible assets\",\"Low cash flow volatility, low operating leverage, and a low level of fungible assets\",\"B\",\"B. Correctbecause an increased ability to support debt is indicated by high revenue, low operating leverage, and greater fungible assets.\"\n\"CI\",\"According to the Modigliani-Miller propositions, if a company's debt-to-equity ratio increases, which of the following costs is most likely to exhibit the largest increase?\",\"WACC\",\"Cost of debt\",\"Cost of equity\",\"C\",\"C. Correct because as the debt-to-equity ratio increases and the company uses more debt, its risk goes up and the cost of equity must increase. MM Proposition II holds that the increase in the cost of equity must exactly offset the greater use of lower cost debt. 52\"\n\"CI\",\"At which stage in its life cycle would a typical company most likely have more debt than equity in its capital structure?\",\"Start-up stage\",\"Growth stage\",\"{ Mature stage\",\"C\",\"C. Correct because at the mature stage, the company becomes able to support low- cost debt, often on an unsecured basis. From the company’s perspective, debt financing is likely to be more attractive than higher-cost equity financing. Also, as companies mature, business risk typically declines, and their cash flows turn positive and become increasingly predictable, allowing for greater use of leverage on more attractive (less costly) financing terms. Debt then becomes a larger component of their\"\n\"CI\",\"Compared to going concern projects, expansion projects most likely involve:\",\"greater uncertainty only.\",\"greater amounts of capital only.\",\"{+ both greater uncertainty and greater amounts of capital.\",\"C\",\"G Correct because expansion projects typically involve greater uncertainty, time, and amounts of capital than going concern projects. 53\"\n\"CI\",\"An improvement in corporate governance structure most likely results in:\",\"lower cost of debt borrowing.\",\"less control by management.\",\"reduced operational efficiency.\",\"A\",\"A. Correct because default risks are also mitigated by properly functioning audit systems, transparent and better reporting of earnings, and controlling information asymmetries between the company and its capital providers. Lower default risks are associated with better credit ratings for the company and lower costs of debt borrowing, given that creditors typically require a lower return when their funds are better secured and their rights protected. Thus, an effective corporate governance struc\"\n\"CI\",\"Consider the following information about a company: Market value of debt outstanding £15,000 Market value of company £40,000 Cost of debt 4.0% Unlevered WACC 9.0% Tax rate 25% Based on the Modigliani-Miller propositions, the company's cost of equity is closest to:\",\"10.4%.\",\"11.3%.\",\"12.0%.\",\"B\",\"B. Correct because Modigliani and Miller also show that the cost of equity for the same company with debt is: r. = ro + (ro- rd)(1 - £)(D/E), where: r. = cost of equity 1, = cost of capital for a company financed only with equity rs = cost of debt D = market value of debt E = market value of equity. Cost of equity = 0.09 + (0.09 - 0.04)x(1 - 0.25)x(£15,000/(£40,000 - 15,000) = 0.1125 = 11.3%.\"\n\"CI\",\"According to the Modigliani and Miller Proposition I with taxes, the value of a levered company is greater than the value of the unlevered company by an amount equal to the:\",\"value of the debt.\",\"after-tax interest paid.\",\"tax rate multiplied by the value of the debt.\",\"C\",\"C. Correct because Modigliani and Miller show that in the presence of corporate taxes (but not personal taxes), the value of the levered company is greater than that of the all- equity company by an amount equal to the tax rate multiplied by the value of the debt, also termed the debt tax shield. 58\"\n\"CI\",\"A measure of how effectively capital is converted into after-tax operating profits is the:\",\"hurdle rate.\",\"costof capital.\",\"return on invested capital.\",\"C\",\"C. Correctbecause ROIC reflects how effectively a company’s management is able to convert capital into after-tax operating profits.\"\n\"CI\",\"A company with a required rate of return of 12% is considering a capital project with the following cash flows (in millions): Initial Outlay Year 1Year 2 Cash flow -£150 £8 £175 B The expected IRR for this project is most likely:\",\"less than 12%.\",\"equal to 12%.\",\"greater than 12%.\",\"A\",\"A. Correct because the IRR is the discount rate that makes the present value of the future after-tax cash flows equal that investment outlay or $+. CF. + (1 + IRR) = Outlay, where IRR is the internal rate of return. Solved using the following calculator inputs: CFs = ~150, CF, = 8, CF: = 175, Calculate IRR = 10.7119, rounded to 10.71% which is less than 12%.\"\n\"CI\",\"All else being equal, if interest on debt is tax deductible, an increase in the company's marginal tax rate will: h\",\"decrease the company's WACC.\",\"not affect the company's WACC.\",\"increase the company's WACC.\",\"A\",\"A. Correct because the marginal cost of debt financing is the cost of debt after considering the allowable deduction for interest on debt. If interest can be deducted in full, 63 the tax deductibility of debt reduces the effective marginal cost of debt to reflect the income shielded from taxation (often referred to as the tax shield) and the marginal cost of debt is ry(1 - t). If the marginal tax rate increases, this increases the tax shield and lowers the marginal cost of debt and also the WACC\"\n\"CI\",\"Which of the following is most accurate?\",\"Risk appetites are similar among private lenders\",\"Staggered boards provide continuous implementation of strategy and oversight\",\"A company's CEO is responsible for implementing the company’s strategy under the oversight of the company's shareholders\",\"B\",\"B. Correct because the positive aspect of a staggered board is that it provides continuous implementation of strategy and oversight without constantly being reassessed by new board members, which otherwise risks bringing short-termism into company strategy.\"\n\"CI\",\"The potential for conflict between debtholders and shareholders is:\",\"lower for long-term debt than for short-term debt.\",\"the same for long-term debt and short-term debt.\",\"higher for long-term debt than for short-term debt.\",\"C\",\"C Correct because the potential debt/equity conflict is greater in the case of long- term rather than short-term debt because the passage of time exposes debtholders to possible changes in business conditions, strategy, and management behavior.\"\n\"CI\",\"Joshua Hu, a research analyst, is initiating coverage on several companies in the ocean freight shipping industry. OldShips is a mature company with high fixed costs and a high capital expenditure to sales ratio because it owns and operates its own fleet of ships. CleanYards is a technologically advanced, sustainable shipyard with a focus on specialized repairs and ship construction. Hu has compiled the following data for the two companies: OldShips CleanYards Degree of Financial Leverage (DFL) 2.0 2.0 Degree of Operating Leverage (DOL) 1.0 2.0 Asset turnover ratio 0.84% 0.42x DSO 27 98 DOH 12 46 DPO 55 40 NewShips, a third company, is a web-based shipping technology platform that connects ship operators such as OldShips with customers in a wide variety of industries who need ocean freight shipping. NewShips’ customers place orders online and pay for freight to be placed on a container to any destination in the world. NewShips’ partners, like OldShips, provide vessels on both long- and short-term charters. In 2X19, NewShips’ platform brokered orders for 900,000 twenty-foot equivalent unit (TEU) containers in aggregate, with an average gross freight rate of USD3,848 per TEU. On 45 average, NewShips’ commission, which it receives as a broker from the customer, was 6% of the freight rate. Question An analyst gathers the following information about a company: Bonds €60 6% Preferred stock €20 8% Common stock €120 15% If the company's marginal tax rate is 40%, its weighted average cost of capital is closest to:\",\"9.7%.\",\"10.9%.\",\"11.6%.\",\"B\",\"B. Correct because the WACC = wary x (1 — t) + Wry + Wire. Where: w. = the market value weight for debt = 60 / (60 + 20 + 120) = 0.30 re= the before-tax cost of debt = 6% t= the company's marginal tax rate = 40% = 0.4 w;, = the market value weight for preferred stock = 20 / (60 + 20 + 120) = 0.10 r, = the marginal cost of preferred stock = 8% w. = the market value weight for equity = 120 / (60 + 20 + 120) = 0.60 r. = the marginal cost of equity = 15% WACC = (0.30 x 6% x (1 - 0.4)) + (0.10 x 8%) \"\n\"CI\",\"The flow of finished goods from manufacturer to wholesaler, retailer, and finally to the end customer best describes a(n):\",\"direct sales strategy.\",\"omnichannel strategy.\",\"€ traditional channel strategy.\",\"C\",\"C. Correct because, for ‘product’ businesses, the traditional channel strategy is typically reflected in the flow of finished goods (e.g. from manufacturer to wholesaler, retailer, and end customer), each with its own physical facilities and with the product sold and purchased at each stage.\"\n\"DER\",\"All else held equal, the value of a European call option is best characterized as having\",\"negative relationship with the price of the underlying.\",\"negative relationship with the volatility of the underlying.\",\"positive relationship with the time to expiration.\",\"C\",\"C. Correct. The value of a European call option is directly related to the time to expiration. That is, all else held equal, the value of a European call option is higher the longer the time to expiration.\"\n\"DER\",\"The value of a European put is directly related to the:\",\"risk-free rate.\",\"exercise price.\",\"value of the underlying.\",\"B\",\"B. Correct because \"\"[t]he value of European put option is directly related to the exercise price.\"\"\"\n\"DER\",\"An investor gathers the following information about a call option: Option premium $5 Exercise price $25 Price of the underlying at initiation ~ $15 At expiration, if the price of the underlying is $30, the value of the call option to the call seller is:\",\"-$5.\",\"$0.\",\"$10.\",\"A\",\"A. Correct because —c; = -Max(0,S: - X) (payoff to the call seller), where -cris the call value at expiration for the call seller, Sis the price of the underlying at expiration, and X is the strike price. Therefore, the Correct calculation yields: -$5 = -Max(0,$30 - $25).\"\n\"DER\",\"An investor takes a long position in a risk-free bond and in a forward contract on a non- dividend-paying stock. The forward contract is priced at £50. The annual risk-free rate is 10%. A nine-month put option on the stock with an exercise price of £47 trades at £4. The price of a nine-month call option on the stock with an exercise price of £47 is closest to:\",\"£6.79.\",\"£7.22.\",\"£7.30.\",\"A\",\"A. Correct because a long put and a short call are equivalent to a long risk-free bond and short forward position: ps =o =[X~Fs(T)](1+r)- as calculated below: Po = Co = [X-Fo(T)](1+1) (4) 87 Rearranging for co: €o= po— [X-Fo(T)](1+41) po=put=£4 X = exercise price = £47 Fu(T) = forward = £50 r = risk-free rate = 10% Po - [X-Fo(T)] (141) 7= co Thus, co = £4 - [E47 - £50](1.10)7 = £6.79\"\n\"DER\",\"Which of the following derivatives have a non-linear payoff?\",\"Contingent claims only\",\"Forward commitments only\",\"Both contingent claims and forward commitments\",\"A\",\"A. Correct because asymmetric payoff profile is a common feature of contingent claims, which are sometimes referred to as non-linear derivatives.\"\n\"DER\",\"‘Which of the following statements about derivatives is most accurate?\",\"Derivatives reduce the efficiency of price discovery for the underlying\",\"Transaction cost of derivatives are greater than the transaction cost of the\",\"underlying 6; Excessive risk taking and use of leverage in derivative markets may contribute to market stress\",\"C\",\"C. Correctbecause excessive risk taking and use of leverage in derivative markets may contribute to market stress, as in the 2008 financial crisis.\"\n\"DER\",\"The potential divergence between the cash flow timing of a derivative instrument versus its underlying best describes:\",\"basis risk.\",\"liquidity risk.\",\"systemic risk.\",\"B\",\"B. Correct because liquidity risk is described as potential divergence between the cash flow timing of a derivative instrument versus an underlying or hedged transaction.\"\n\"DER\",\"The value of a forward contract at initiation is most likely equal to:\",\"zero.\",\"the spot price minus the forward price.\",\"the forward price minus the spot price.\",\"A\",\"A. Correct because neither the long nor the short pays anything to the other at the initiation date of a forward contract, the value of a forward contract when initiated is zero.\"\n\"DER\",\"In the over-the-counter derivatives market, most transactions occur between end usersand:\",\"dealers.\",\"other end users.\",\"[] a central counterparty.\",\"A\",\"A. Correct because OTC (over-the-counter) derivative markets involve contracts entered between derivatives end users and dealers, or financial intermediaries, such as commercial banks or investment banks.\"\n\"DER\",\"Long futures contracts are more attractive than long forward positions for the sameunderlying and maturity when futures prices and interest rates are:\",\"negatively correlated.\",\"uncorrelated.\",\"positively correlated.\",\"C\",\"C. Correct because the different patterns of cash flows for forwards and futures can lead to a difference in the pricing of forwards versus futures and if futures prices are positively correlated with interest rates, long futures contracts are more attractive than long forward positions for the same underlying and maturity. The reason is because rising prices lead to futures profits that are reinvested in periods of rising interest rates, and falling prices lead to losses that occur in periods o\"\n\"DER\",\"An analyst collects the following information: Current stock price €26 Gross return from an up move 1.10 Gross return from a down move 0.75 Call and put exercise price €22 Based on a one-period binomial pricing model, which of the following has the largest payoff?\",\"Put option following an up move\",\"Put option following a down move\",\"Call option following a down move\",\"B\",\"B. Correct because the payoff of a put option following a down move is p. = Max (0, X ~ Si) where X is the exercise price and Sis the price after a down move. In this case, Sy = 100 €26(0.75) = €19.50. So, px = Max (0, €22 - €19.50) = €2.50, which is greater than the payoffs of other two responses.\"\n\"DER\",\"A $10 million interest rate swap with annual payments has a fixed swap rate of 1.95%. The implied forward rates are: Yearimplied Forward Rate (%]) 1 0.50 2 115 3 1.35 The periodic settlement value in Year 3 for the fixed-rate payer is expected to be closest to\",\"-$95,000.\",\"-$60,000.\",\"$60,000.\",\"B\",\"B. Correct because the periodic settlement value = (MRR - sy) x Notional amount x Period. The market reference rate (MMR) for Year 3 is 1.35%, thus: = (0.0135 - 0.0195) x $10,000,000 x 1 = -$60,000.\"\n\"DER\",\"Which of the following best describes put-call-forward parity? A The present value of the exercise price plus the call price equals the put price plus\",\"underlying price.\",\"The underlying price plus the call price equals the present value of the exercise\",\"price plus the put price. C. The call price minus the put price equals the present value of the exercise price minus the underlying price.\",\"A\",\"A Correct because the put price plus the underlying price equals the call price plus the present value of the exercise price. Rearranged, this is as follows: The present value of the exercise price plus the call price equals the put price plus the underlying price.\"\n\"DER\",\"An end user seeking to hedge a specific underlying exposure having non-standard size and settlement dates would most likely trade on a(n):\",\"futures market.\",\"over-the-counter derivative market.\",\"exchange-traded derivative market.\",\"B\",\"B. Correct because the terms of OTC (over-the-counter) contracts can be customized to match a desired risk exposure profile. This flexibility is important to end users seeking to hedge a specific existing or anticipated underlying exposure based upon non-standard terms.\"\n\"DER\",\"An investor buys a call for $5.75 that has a strike price of $130. If the value at expiration forthis call is $17.80, the price of the underlying at expiration is closest to:\",\"$112.20.\",\"$142.05\",\"$147.80.\",\"C\",\"C Correct because the value or \"\"payoff to the call buyer\"\" at expiration is c. = Max(0,S: - X) where X is the strike price, Sis the price of the underlying at expiration. Given the information in the stem we get $17.80 = Max(0,S: — $130). Hence, S; =$ 130 + $17.80 = $147.80.\"\n\"DER\",\"An investor sells a European put option with the following characteristics: Put price 30 Exercise price 1,320 If the price of the underlying at expiration is 1,340, the profit for the seller is\",\"10.\",\"20.\",\"30.\",\"C\",\"C. Correct because to the put seller, the profit is I = -Max(0,X - S7) + po, where X is the exercise price, Sis the price of the underlying at expiration, and po is the put price. Therefore, IT = -Max(0,(1,320 - 1,340)) + 30 = 30.\"\n\"DER\",\"An analyst gathers the following information about three portfolios each consisting of two derivatives on the same underlying: — Forward PositionOption Position Portfolio 1 Long Long Call Portfolio 2 Long Long Put Portfolio 3 Short Long Call All else being equal, which portfolio will benefit from an increase in price of the underlying?\",\"Portfolio 1\",\"Portfolio 2\",\"Portfolio\",\"A\",\"A. Correct because both a long forward position and a long call option position will gain from an increase in the underlying price.\"\n\"DER\",\"An investor collects the following information about a put option: Stock price at initiation $220 Strike price $210 Option premium $9 At expiration, if the price of the stock is $200, the investor's profit from buying the put is\",\"-$19.\",\"-$9.\",\"$1.\",\"B\",\"incorrect calculation yields: -$19 = $200 - $220 + Max(0,$210 - $200) - $9, which includes the loss of $20 of the underlying. Instead, the correct formula is I1 = Max(0,X - 57) ~ po (profit to the put buyer) which yields: $1 = Max(0,$210 - $200) - $9.\"\n\"DER\",\"Which of the following interest rate derivatives most likely has the largest convexity bias?\",\"Forward rate agreement on a 1-month market reference rate\",\"Forward rate agreement on a 3-month market reference rate\",\"Interest rate futures contract on a 3-month market reference rate\",\"B\",\"B. Correct because the discounting feature of the FRA, which is not present in the futures contract, leads to a convexity bias that is greater for longer discounting periods. Since the length of the discounting period depends on the maturity of the underlying market reference rate, 3-month market reference rate results in a longer discounting period than the 1-month rate.\"\n\"ECO\",\"The inflation target of an effective central bank is most likely:\",\"equal to zero to avoid the risk of deflation.\",\"sufficiently below zero to maintain high credibility.\",\"low enough to ensure a significant degree of price stability.\",\"C\",\"C. Correctbecause an inflation-targeting framework normally has a clear, symmetric and forward-looking medium-term inflation target, sufficiently above 0 percent to avoid the risk of deflation but low enough to ensure a significant degree of price stability.\"\n\"ECO\",\"Cyber threats most likely fall into the category of:\",\"event risk.\",\"thematic risk.\",\"C. exogenous risk.\",\"B\",\"B. Correct because cyber threats are another example of thematic risk.\"\n\"ECO\",\"Fiat money:\",\"is not currently used in any major economy.\",\"can be exchanged for a precious metal at the country's central bank.\",\"derives its value via government decree and because people accept it for payment.\",\"C\",\"C. Correct because fiat money derives its value via government decree and because people accept it for payment of goods and services and for debt repayment.\"\n\"ECO\",\"With respect to conventional monetary policy, combating inflation is most likely:\",\"less difficult than combating deflation.\",\"equally difficult as combating deflation.\",\"more difficult than combating deflation.\",\"A\",\"A. Correct because deflation is more difficult for conventional monetary policy to deal with than inflation. This is because once the monetary authority has cut nominal interest rates to zero to stimulate the economy, it cannot cut them any further.\"\n\"ECO\",\"Assuming wages and prices are rigid, which of the following policy combinations most likely leads to the private sector increasing its share of GDP?\",\"Easy fiscal policy and tight monetary policy\",\"Tight monetary policy and tight fiscal policy\",\"Tight fiscal policy and easy monetary policy\",\"C\",\"Gh. Correct because if a fiscal contraction is accompanied by expansionary monetary policy and low interest rates, then the private sector will be stimulated and will rise as a share of GDP, while the public sector will shrink.\"\n\"ECO\",\"Under monopolistic competition, a firm's supply curve is represented by:\",\"average cost.\",\"marginal cost.\",\"neither average cost nor marginal cost.\",\"C\",\"C. Correctbecause in perfect competition, the firm's supply schedule is represented by the marginal cost schedule. In monopolistic competition, there is no well-defined supply function. The information used to determine the appropriate level of output is based on the intersection of MC and MR. However, the price that will be charged is based on the market demand schedule. The firm's supply curve should measure the quantity the firm is willing to supply at various prices. That information is not \"\n\"ECO\",\"An analyst gathers the following foreign exchange rate information: CAD/USDJPY/USD Beginning of period 1.3216 105.42 End of period 1.2944 104.74 CAD/USD is the amount of CAD per 1 USD. JPY/USD is the amount of JPY per 1 USD. The percentage change in the JPY/CAD cross-rate for the period is closest to\",\"2.7%.\",\"1.4%.\",\"2.8%.\",\"B\",\"correct calculation: Beginning of period JPY/CAD rate = 1.3216 x 105.42 = 139.32 End of period JPY/CAD exchange rate = 1.2944 x 104.74 = 135.58 Therefore the percentage change in JPY/CAD was calculated incorrectly as 135.58/139.32 - 1 =-2.68% =~ 2.7%.\"\n\"ECO\",\"An analyst gathers the following information: Foreign inflation rate 2% Domestic inflation rate 3% Nominal appreciation of domestic currency against foreign currency ~~ 6% The real appreciation of the domestic currency against the foreign currency is closest to\",\"4%.\",\"5%.\",\"7%.\",\"B\",\"B. Correct because the change in the real exchange rate is (1+ ASd/,/Sd/) x (1+ AP/Pf) / (1 + APP) — 1 = (1+ 6%) x (1+ 2%)/(1 + 3%) —1=1.06 x 1.02/1.03 — 1 = 0.0497 = 0.05 = 5%, where ASd/,/Sd/;is the change of the nominal exchange rate, AP;/Pfis the foreign inflation rate, and AP./Puis the domestic inflation rate. Using the appropriate approximate formula, 6.0% + 2.0% - 3.0% = 5% leads to the same answer choice.\"\n\"ECO\",\"With respect to trading blocs, a common market most likely incorporates all aspects of a(n):\",\"customs union.\",\"monetary union.\",\"economic union.\",\"A\",\"A. Correct because the common market is the next level of economic integration that incorporates all aspects of the customs union and extends it by allowing free movement of factors of production among members.\"\n\"ECO\",\"Which of the following is most likely to limit the effectiveness of monetary policy?\",\"Aliquidity trap\",\"The crowding out effect\",\"A time lag to implement government spending\",\"A\",\"A. Correct because there may be occasions where the demand for money becomes infinitely elastic so that further injections of money into the economy will not serve to further lower interest rates or affect real activity. This is known as a liquidity trap. In this extreme circumstance, monetary policy can become completely ineffective.\"\n\"ECO\",\"The main objective of the World Bank Group is to:\",\"support exchange rate stability and an open system of international payments.\",\"provide the legal and institutional foundation of the multinational trading system.\",\"help developing countries fight poverty and enhance environmentally sound economic growth.\",\"C\",\"C. Correctbecause the World Bank's main objective is to help developing countries fight poverty and enhance environmentally sound economic growth.\"\n\"ECO\",\"If the spot rate for AUD/USD (amount of AUD per 1 USD) is 1.4780 and the 1-month forward points are -16.0, the 1-month forward rate for AUD/USD is closest to:\",\"1.3180.\",\"1.4764.\",\"1.4796.\",\"B\",\"B. Correct because to convert any of these quoted forward points into a forward rate, one would divide the number of points by 10,000 (to scale down to the fourth decimal place, the last decimal place in the spot quote) and then add the result to the spot exchange rate quote. The forward points are negative and therefore the forward rate = ~16/10,000 + 1.4780 = -0.0016 + 1.4780 = 1.4764. 155\"\n\"ECO\",\"When a central bank sells government bonds to commercial banks, broad money growth:\",\"decreases.\",\"remains the same.\",\"increases.\",\"A\",\"A Correct because when a central bank sells government bonds to a commercial bank the reserves of commercial banks decline, reducing their capacity to make loans (i.e, create credit) to households and corporations and thus causing broad money growth to decline through the money multiplier mechanism.\"\n\"ECO\",\"An analyst gathers the following information (in $ millions) about a firm operating ina perfectly competitive market: Total variable costs 700 Total fixed costs 400 If the firm's total revenue is $1,000 million, the firm should:\",\"stay in the market in both the short run and long run.\",\"stay in the market in the short run and exit the market in the long run.\",\"shutdown production in the short run and exit the market in the long run.\",\"B\",\"B. Correct because when TR total revenue is enough to cover TVC (total variable costs) but not all of TFC total fixed costs, the firm can continue to produce in the short run but will be unable to maintain financial solvency in the long run. TR is $1,000 which is greater than TVC of $700, but not enough to cover the firm's TFC of $400. Therefore the firm will exit the market in the long run.\"\n\"ECO\",\"Natural disasters are an example of:\",\"event risk.\",\"thematic risk.\",\"exogenous risk.\",\"C\",\"C Correct because exogenous risk is a sudden or unanticipated risk that impacts either a country’s cooperative stance, the ability of non-state actors to globalize, or both. Examples include sudden uprisings, invasions, or the aftermath of natural disasters.\"\n\"ECO\",\"During the recovery phase of the business cycle, inflation most likely:\",\"remains moderate.\",\"further accelerates.\",\"decelerates but with a lag.\",\"A\",\"A. Correct because, in the “recovery” phase, inflation remains moderate.\"\n\"ECO\",\"The Herfindahl-Hirschman index is calculated based on:\",\"market shares of the companies.\",\"elasticity of demand in the market.\",\"probability of new entry into the market. 127 Economics: Practice Pack - Answers\",\"A\",\"A Correct because in calculating the Herfindahl-Hirschman index the market shares of the top N companies are first squared and then added. If one firm controls the whole market (a monopoly), the Herfindahl-Hirschman index (HHI) equals 1. If there are M firmsin the industry with equal market shares, then the HHI equals (1/M).\"\n";

export async function GET(req: NextRequest) {
  if (req.nextUrl.searchParams.get("go") !== "1") {
    return NextResponse.json({ hint: "append ?go=1 to import", batch: "examq2", count: 261 });
  }
  const lines = QUESTIONS_CSV.split("\n");
  const header = lines[0];
  const rows = lines.slice(1).filter((l) => l.trim());
  let added = 0;
  let skipped = 0;
  for (let i = 0; i < rows.length; i += 120) {
    const chunk = header + "\n" + rows.slice(i, i + 120).join("\n") + "\n";
    const res = await importQuestionsCsv(chunk);
    added += res.added;
    skipped += res.skipped;
  }
  return NextResponse.json({ ok: true, questions: { added, skipped } });
}
